{
  "name": "CONTAS LEBOL",
  "description": "Um gerenciador financeiro completo para controle de contas pessoais e domésticas, permitindo o acompanhamento de gastos rotineiros e eventuais com insights inteligentes por IA."
}

import React from 'react';
import ReactDOM from 'react-dom/client';
import App from './App';

const rootElement = document.getElementById('root');
if (!rootElement) {
  throw new Error("Could not find root element to mount to");
}

const root = ReactDOM.createRoot(rootElement);
root.render(
  <React.StrictMode>
    <App />
  </React.StrictMode>
);

export enum FrequencyType {
  WEEKLY = 'Semanal',
  MONTHLY = 'Mensal',
  ONE_TIME = 'Único'
}

export enum ExpenseNature {
  ROUTINE = 'Rotineiro',
  EVENTUAL = 'Eventual'
}

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  date: string;
  category: string;
  frequency: FrequencyType;
  nature: ExpenseNature;
}

export interface CategorySummary {
  name: string;
  value: number;
  color: string;
}

import { GoogleGenAI } from "@google/genai";
import { Transaction } from "../types";

export const getFinancialInsights = async (transactions: Transaction[]): Promise<string> => {
  const ai = new GoogleGenAI({ apiKey: process.env.API_KEY });

  const summary = transactions.map(t => 
    `- ${t.description}: R$${t.amount} (${t.category}, ${t.frequency}, ${t.nature})`
  ).join('\n');

  const prompt = `
    Como um consultor financeiro especialista para o aplicativo "CONTAS LEBOL", analise os seguintes gastos domésticos e pessoais e forneça insights curtos e práticos (em 3 tópicos) para economizar ou organizar melhor as contas:

    ${summary}

    Responda em português de forma amigável e direta. Foque na distinção entre gastos rotineiros e eventuais.
  `;

  try {
    const response = await ai.models.generateContent({
      model: 'gemini-3-flash-preview',
      contents: prompt,
    });
    return response.text || "Não foi possível gerar insights no momento.";
  } catch (error) {
    console.error("Erro ao chamar Gemini:", error);
    return "Ops! O consultor IA está ocupado agora. Tente novamente mais tarde.";
  }
};

import React, { useState } from 'react';
import { FrequencyType, ExpenseNature, Transaction } from '../types';
import { CATEGORIES } from '../constants';

interface TransactionFormProps {
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
  onClose: () => void;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ onAdd, onClose }) => {
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [category, setCategory] = useState(CATEGORIES[0].name);
  const [frequency, setFrequency] = useState<FrequencyType>(FrequencyType.MONTHLY);
  const [nature, setNature] = useState<ExpenseNature>(ExpenseNature.ROUTINE);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    onAdd({
      description,
      amount: parseFloat(amount),
      date,
      category,
      frequency,
      nature
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4 z-50">
      <div className="bg-white rounded-2xl w-full max-w-md p-6 shadow-2xl">
        <h2 className="text-2xl font-bold mb-6 text-slate-800">Nova Conta</h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Descrição</label>
            <input
              type="text"
              required
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              placeholder="Ex: Aluguel, Supermercado..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Valor (R$)</label>
              <input
                type="number"
                step="0.01"
                required
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="0,00"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Data</label>
              <input
                type="date"
                required
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                value={date}
                onChange={(e) => setDate(e.target.value)}
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Categoria</label>
            <select
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
              value={category}
              onChange={(e) => setCategory(e.target.value)}
            >
              {CATEGORIES.map(cat => (
                <option key={cat.name} value={cat.name}>{cat.name}</option>
              ))}
            </select>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Frequência</label>
              <select
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                value={frequency}
                onChange={(e) => setFrequency(e.target.value as FrequencyType)}
              >
                <option value={FrequencyType.WEEKLY}>Semanal</option>
                <option value={FrequencyType.MONTHLY}>Mensal</option>
                <option value={FrequencyType.ONE_TIME}>Único</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Natureza</label>
              <select
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                value={nature}
                onChange={(e) => setNature(e.target.value as ExpenseNature)}
              >
                <option value={ExpenseNature.ROUTINE}>Rotineiro</option>
                <option value={ExpenseNature.EVENTUAL}>Eventual</option>
              </select>
            </div>
          </div>

          <div className="flex gap-3 pt-4">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-2 rounded-lg bg-slate-100 text-slate-600 font-medium hover:bg-slate-200 transition-colors"
            >
              Cancelar
            </button>
            <button
              type="submit"
              className="flex-1 px-4 py-2 rounded-lg bg-blue-600 text-white font-medium hover:bg-blue-700 transition-colors shadow-lg shadow-blue-200"
            >
              Salvar
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default TransactionForm;

import React from 'react';
import { PieChart, Pie, Cell, ResponsiveContainer, BarChart, Bar, XAxis, YAxis, Tooltip, Legend } from 'recharts';
import { Transaction } from '../types';
import { CATEGORIES } from '../constants';

interface DashboardProps {
  transactions: Transaction[];
}

const Dashboard: React.FC<DashboardProps> = ({ transactions }) => {
  const totalBalance = transactions.reduce((acc, curr) => acc + curr.amount, 0);

  const categoryData = CATEGORIES.map(cat => ({
    name: cat.name,
    value: transactions
      .filter(t => t.category === cat.name)
      .reduce((acc, curr) => acc + curr.amount, 0),
    color: cat.color
  })).filter(c => c.value > 0);

  const routineTotal = transactions
    .filter(t => t.nature === 'Rotineiro')
    .reduce((acc, curr) => acc + curr.amount, 0);

  const eventualTotal = transactions
    .filter(t => t.nature === 'Eventual')
    .reduce((acc, curr) => acc + curr.amount, 0);

  const frequencyData = [
    { name: 'Rotineiros', valor: routineTotal },
    { name: 'Eventuais', valor: eventualTotal }
  ];

  return (
    <div className="space-y-6">
      <div className="grid grid-cols-1 md:grid-cols-3 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <p className="text-sm font-medium text-slate-500 mb-1">Total Acumulado</p>
          <h3 className="text-3xl font-bold text-slate-900">R$ {totalBalance.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
          <div className="mt-2 text-xs text-slate-400">Total histórico de lançamentos</div>
        </div>
        <div className="bg-blue-50 p-6 rounded-2xl shadow-sm border border-blue-100">
          <p className="text-sm font-medium text-blue-600 mb-1">Gastos Rotineiros</p>
          <h3 className="text-3xl font-bold text-blue-800">R$ {routineTotal.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
          <div className="mt-2 text-xs text-blue-600/70">Contas fixas e recorrentes</div>
        </div>
        <div className="bg-amber-50 p-6 rounded-2xl shadow-sm border border-amber-100">
          <p className="text-sm font-medium text-amber-600 mb-1">Gastos Eventuais</p>
          <h3 className="text-3xl font-bold text-amber-800">R$ {eventualTotal.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}</h3>
          <div className="mt-2 text-xs text-amber-600/70">Lançamentos esporádicos</div>
        </div>
      </div>

      <div className="grid grid-cols-1 lg:grid-cols-2 gap-6">
        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h4 className="text-lg font-semibold mb-6 text-slate-800">Distribuição por Categoria</h4>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <PieChart>
                <Pie
                  data={categoryData}
                  cx="50%"
                  cy="50%"
                  innerRadius={60}
                  outerRadius={100}
                  paddingAngle={5}
                  dataKey="value"
                >
                  {categoryData.map((entry, index) => (
                    <Cell key={`cell-${index}`} fill={entry.color} />
                  ))}
                </Pie>
                <Tooltip 
                  formatter={(value: number) => `R$ ${value.toLocaleString('pt-BR')}`}
                  contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Legend layout="vertical" align="right" verticalAlign="middle" />
              </PieChart>
            </ResponsiveContainer>
          </div>
        </div>

        <div className="bg-white p-6 rounded-2xl shadow-sm border border-slate-100">
          <h4 className="text-lg font-semibold mb-6 text-slate-800">Rotina vs Eventual</h4>
          <div className="h-[300px] w-full">
            <ResponsiveContainer width="100%" height="100%">
              <BarChart data={frequencyData}>
                <XAxis dataKey="name" axisLine={false} tickLine={false} />
                <YAxis axisLine={false} tickLine={false} hide />
                <Tooltip 
                   formatter={(value: number) => `R$ ${value.toLocaleString('pt-BR')}`}
                   cursor={{ fill: '#f8fafc' }}
                   contentStyle={{ borderRadius: '12px', border: 'none', boxShadow: '0 4px 6px -1px rgb(0 0 0 / 0.1)' }}
                />
                <Bar dataKey="valor" radius={[10, 10, 0, 0]}>
                  <Cell fill="#3b82f6" />
                  <Cell fill="#f59e0b" />
                </Bar>
              </BarChart>
            </ResponsiveContainer>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Dashboard;

import React, { useState, useEffect, useCallback } from 'react';
import { Transaction, FrequencyType, ExpenseNature } from './types';
import { INITIAL_TRANSACTIONS, CATEGORIES } from './constants';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import { getFinancialInsights } from './services/geminiService';

const App: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('contas_lebol_data');
    return saved ? JSON.parse(saved) : INITIAL_TRANSACTIONS;
  });
  const [isFormOpen, setIsFormOpen] = useState(false);
  const [aiInsights, setAiInsights] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [filter, setFilter] = useState<'all' | 'Rotineiro' | 'Eventual'>('all');

  useEffect(() => {
    localStorage.setItem('contas_lebol_data', JSON.stringify(transactions));
  }, [transactions]);

  const addTransaction = (newTx: Omit<Transaction, 'id'>) => {
    const transaction: Transaction = {
      ...newTx,
      id: Math.random().toString(36).substr(2, 9),
    };
    setTransactions(prev => [transaction, ...prev]);
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Tem certeza que deseja excluir este lançamento?')) {
      setTransactions(prev => prev.filter(t => t.id !== id));
    }
  };

  const generateInsights = async () => {
    if (transactions.length === 0) return;
    setIsAiLoading(true);
    setAiInsights(null);
    try {
      const insights = await getFinancialInsights(transactions);
      setAiInsights(insights);
    } finally {
      setIsAiLoading(false);
    }
  };

  const filteredTransactions = transactions.filter(t => 
    filter === 'all' ? true : t.nature === filter
  );

  return (
    <div className="min-h-screen pb-24 lg:pb-8">
      {/* Header */}
      <header className="bg-white border-b border-slate-100 sticky top-0 z-40 px-4 py-4 md:px-8">
        <div className="max-w-7xl mx-auto flex justify-between items-center">
          <div className="flex items-center gap-2">
            <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-blue-200">
              L
            </div>
            <div>
              <h1 className="text-xl font-bold text-slate-800 leading-tight">CONTAS LEBOL</h1>
              <p className="text-xs text-slate-500 font-medium tracking-wider">GESTÃO INTELIGENTE</p>
            </div>
          </div>
          <button
            onClick={() => setIsFormOpen(true)}
            className="hidden md:flex items-center gap-2 bg-blue-600 hover:bg-blue-700 text-white px-5 py-2.5 rounded-xl font-semibold transition-all shadow-lg shadow-blue-100"
          >
            <span className="text-lg">+</span> Nova Conta
          </button>
        </div>
      </header>

      <main className="max-w-7xl mx-auto px-4 py-8 md:px-8 space-y-8">
        {/* Dashboard Section */}
        <section>
          <div className="flex justify-between items-center mb-6">
            <h2 className="text-xl font-bold text-slate-800">Visão Geral</h2>
            <button 
              onClick={generateInsights}
              disabled={isAiLoading}
              className={`text-sm flex items-center gap-2 font-semibold px-4 py-2 rounded-full border border-slate-200 bg-white transition-all
                ${isAiLoading ? 'opacity-50 cursor-not-allowed' : 'hover:bg-blue-50 hover:border-blue-200 hover:text-blue-600'}`}
            >
              {isAiLoading ? (
                <span className="flex items-center gap-2">
                   <div className="w-3 h-3 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                   Analisando...
                </span>
              ) : (
                <>✨ Consultoria IA</>
              )}
            </button>
          </div>

          {aiInsights && (
            <div className="mb-8 p-6 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-2xl text-white shadow-xl relative overflow-hidden">
              <div className="absolute top-0 right-0 p-4 opacity-10">
                <svg width="100" height="100" viewBox="0 0 24 24" fill="currentColor"><path d="M12 2L4.5 20.29l.71.71L12 18l6.79 3 .71-.71z"/></svg>
              </div>
              <h3 className="text-lg font-bold mb-3 flex items-center gap-2">
                Conselhos do Lebol IA
              </h3>
              <div className="text-blue-50 whitespace-pre-line text-sm leading-relaxed">
                {aiInsights}
              </div>
              <button 
                onClick={() => setAiInsights(null)}
                className="mt-4 text-xs font-bold text-white/60 hover:text-white uppercase tracking-widest"
              >
                Fechar Dicas
              </button>
            </div>
          )}

          <Dashboard transactions={transactions} />
        </section>

        {/* Transactions Section */}
        <section className="space-y-6">
          <div className="flex flex-col md:flex-row md:items-center justify-between gap-4">
            <h2 className="text-xl font-bold text-slate-800">Histórico de Contas</h2>
            <div className="flex p-1 bg-slate-100 rounded-xl self-start">
              <button 
                onClick={() => setFilter('all')}
                className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-all ${filter === 'all' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                Todos
              </button>
              <button 
                onClick={() => setFilter('Rotineiro')}
                className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-all ${filter === 'Rotineiro' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                Rotina
              </button>
              <button 
                onClick={() => setFilter('Eventual')}
                className={`px-4 py-1.5 rounded-lg text-sm font-semibold transition-all ${filter === 'Eventual' ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}
              >
                Eventual
              </button>
            </div>
          </div>

          <div className="bg-white rounded-2xl border border-slate-100 overflow-hidden shadow-sm">
            <div className="overflow-x-auto">
              <table className="w-full text-left">
                <thead>
                  <tr className="bg-slate-50 text-slate-500 text-xs font-bold uppercase tracking-wider">
                    <th className="px-6 py-4">Data</th>
                    <th className="px-6 py-4">Descrição</th>
                    <th className="px-6 py-4">Categoria</th>
                    <th className="px-6 py-4">Freq. / Natureza</th>
                    <th className="px-6 py-4 text-right">Valor</th>
                    <th className="px-6 py-4 text-center">Ações</th>
                  </tr>
                </thead>
                <tbody className="divide-y divide-slate-50">
                  {filteredTransactions.length > 0 ? filteredTransactions.map((tx) => (
                    <tr key={tx.id} className="hover:bg-slate-50/50 transition-colors">
                      <td className="px-6 py-4 text-sm text-slate-600 whitespace-nowrap">
                        {new Date(tx.date).toLocaleDateString('pt-BR')}
                      </td>
                      <td className="px-6 py-4">
                        <p className="text-sm font-semibold text-slate-800">{tx.description}</p>
                      </td>
                      <td className="px-6 py-4">
                        <span className="text-xs font-medium px-2.5 py-1 rounded-full bg-slate-100 text-slate-600">
                          {tx.category}
                        </span>
                      </td>
                      <td className="px-6 py-4">
                        <div className="flex flex-col gap-1">
                          <span className={`text-[10px] font-bold uppercase tracking-tight px-2 py-0.5 rounded w-fit ${tx.nature === 'Rotineiro' ? 'bg-blue-100 text-blue-700' : 'bg-amber-100 text-amber-700'}`}>
                            {tx.nature}
                          </span>
                          <span className="text-[10px] text-slate-400 font-medium px-2">{tx.frequency}</span>
                        </div>
                      </td>
                      <td className="px-6 py-4 text-right">
                        <span className="text-sm font-bold text-slate-900">
                          R$ {tx.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                        </span>
                      </td>
                      <td className="px-6 py-4 text-center">
                        <button 
                          onClick={() => deleteTransaction(tx.id)}
                          className="text-slate-300 hover:text-red-500 transition-colors p-2"
                        >
                          <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M3 6h18m-2 0v14a2 2 0 01-2 2H7a2 2 0 01-2-2V6m3 0V4a2 2 0 012-2h4a2 2 0 012 2v2"/></svg>
                        </button>
                      </td>
                    </tr>
                  )) : (
                    <tr>
                      <td colSpan={6} className="px-6 py-12 text-center text-slate-400 italic">
                        Nenhum lançamento encontrado.
                      </td>
                    </tr>
                  )}
                </tbody>
              </table>
            </div>
          </div>
        </section>
      </main>

      {/* Mobile FAB */}
      <button
        onClick={() => setIsFormOpen(true)}
        className="fixed bottom-6 right-6 md:hidden w-14 h-14 bg-blue-600 text-white rounded-full flex items-center justify-center text-3xl shadow-xl shadow-blue-300 active:scale-90 transition-transform z-50"
      >
        +
      </button>

      {isFormOpen && (
        <TransactionForm
          onAdd={addTransaction}
          onClose={() => setIsFormOpen(false)}
        />
      )}

      {/* Footer Branding */}
      <footer className="text-center py-8 text-slate-400 text-xs">
        &copy; 2024 CONTAS LEBOL - Gerenciamento Financeiro Familiar
      </footer>
    </div>
  );
};

export default App;

export enum FrequencyType {
  WEEKLY = 'Semanal',
  MONTHLY = 'Mensal',
  ONE_TIME = 'Único'
}

export enum ExpenseNature {
  ROUTINE = 'Rotineiro',
  EVENTUAL = 'Eventual'
}

export enum TransactionType {
  EXPENSE = 'Despesa',
  INCOME = 'Remuneração',
  INVESTMENT = 'Investimento'
}

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  date: string;
  category: string;
  frequency: FrequencyType;
  nature: ExpenseNature;
  type: TransactionType;
}

export interface CategorySummary {
  name: string;
  value: number;
  color: string;
}

export type ViewType = 'dashboard' | 'expenses' | 'income' | 'investments';

import React, { useState } from 'react';
import { FrequencyType, ExpenseNature, Transaction, TransactionType } from '../types';
import { CATEGORIES } from '../constants';

interface TransactionFormProps {
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
  onClose: () => void;
  initialType?: TransactionType;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ onAdd, onClose, initialType = TransactionType.EXPENSE }) => {
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<TransactionType>(initialType);
  const [category, setCategory] = useState(CATEGORIES[0].name);
  const [frequency, setFrequency] = useState<FrequencyType>(FrequencyType.MONTHLY);
  const [nature, setNature] = useState<ExpenseNature>(ExpenseNature.ROUTINE);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    onAdd({
      description,
      amount: parseFloat(amount),
      date,
      category,
      frequency,
      nature,
      type
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4 z-50">
      <div className="bg-white rounded-2xl w-full max-w-md p-6 shadow-2xl">
        <h2 className="text-2xl font-bold mb-6 text-slate-800">Novo Lançamento</h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="flex p-1 bg-slate-100 rounded-xl mb-4">
            {Object.values(TransactionType).map((t) => (
              <button
                key={t}
                type="button"
                onClick={() => setType(t)}
                className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${
                  type === t ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                {t}
              </button>
            ))}
