              </div>

              <button 
                onClick={generateInsights}
                disabled={isAiLoading}
                className={`text-sm flex items-center gap-2 font-bold px-5 py-2.5 rounded-xl border border-slate-200 bg-white shadow-sm transition-all
                  ${isAiLoading ? 'opacity-50 cursor-not-allowed' : 'hover:bg-blue-50 hover:border-blue-200 hover:text-blue-600 active:scale-95'}`}
              >
                {isAiLoading ? (
                  <span className="flex items-center gap-2">
                    <div className="w-4 h-4 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>
                    Analisando finanças...
                  </span>
                ) : (
                  <>✨ Consultoria Inteligente</>
