                                <span className="font-medium">Nada por aqui ainda.</span>
                             </div>
                          </td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </section>
          </div>
        </main>
      </div>

      {/* Navigation Mobile - Fixed Bottom */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 px-6 py-3 flex justify-between items-center z-40">
        <button onClick={() => setCurrentView('dashboard')} className={`p-2 rounded-xl ${currentView === 'dashboard' ? 'text-blue-600' : 'text-slate-400'}`}>
          <svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="7" rx="1"/><rect x="14" y="14" width="7" height="7" rx="1"/><rect x="3" y="14" width="7" height="7" rx="1"/></svg>
        </button>
        <button onClick={() => setCurrentView('expenses')} className={`p-2 rounded-xl ${currentView === 'expenses' ? 'text-blue-600' : 'text-slate-400'}`}>
          <svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M12 8c-1.657 0-3 .895-3 2s1.343 2 3 2 3 .895 3 2-1.343 2-3 2m0-8c1.11 0 2.08.407 2.5 1M12 8V7m0 1v8m0 0v1m0-1c-1.11 0-2.08-.407-2.5-1M21 12a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
        </button>
        <div className="mb-8">
           <button 
            onClick={() => handleCadastrarClick(TransactionType.EXPENSE)}
            className="w-14 h-14 bg-blue-600 text-white rounded-2xl flex items-center justify-center text-3xl shadow-xl shadow-blue-300 active:scale-90 transition-transform"
          >
            +
          </button>
        </div>
        <button onClick={() => setCurrentView('income')} className={`p-2 rounded-xl ${currentView === 'income' ? 'text-blue-600' : 'text-slate-400'}`}>
          <svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"/></svg>
        </button>
        <button onClick={() => setCurrentView('investments')} className={`p-2 rounded-xl ${currentView === 'investments' ? 'text-blue-600' : 'text-slate-400'}`}>
          <svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>
        </button>
      </nav>

      {isFormOpen && (
        <TransactionForm
          initialType={formInitialType}
          onAdd={addTransaction}
          onClose={() => setIsFormOpen(false)}
        />
      )}
    </div>
  );
};

export default App;

export enum FrequencyType {
  WEEKLY = 'Semanal',
  MONTHLY = 'Mensal',
  ANNUAL = 'Anual',
  ONE_TIME = 'Único'
}

export enum ExpenseNature {
  ROUTINE = 'Rotineiro',
  EVENTUAL = 'Eventual'
}

export enum TransactionType {
  EXPENSE = 'Despesa',
  INCOME = 'Remuneração',
  INVESTMENT = 'Investimento'
}

export enum TransactionScope {
  INDIVIDUAL = 'Individual',
  DOMESTIC = 'Doméstica'
}

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  date: string;
  category: string;
  frequency: FrequencyType;
  nature: ExpenseNature;
  type: TransactionType;
  scope: TransactionScope;
}

export interface CategorySummary {
  name: string;
  value: number;
  color: string;
}

export type ViewType = 'dashboard' | 'expenses_individual' | 'expenses_domestic' | 'income' | 'investments';
export type ExpenseSubTab = 'all' | 'annuais' | 'mensais' | 'semanais' | 'eventuais';

import React, { useState } from 'react';
import { FrequencyType, ExpenseNature, Transaction, TransactionType, TransactionScope } from '../types';
import { CATEGORIES } from '../constants';

interface TransactionFormProps {
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
  onClose: () => void;
  initialType?: TransactionType;
  initialScope?: TransactionScope;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ 
  onAdd, 
  onClose, 
  initialType = TransactionType.EXPENSE,
  initialScope = TransactionScope.INDIVIDUAL 
}) => {
  const [description, setDescription] = useState('');
  const [amount, setAmount] = useState('');
  const [date, setDate] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<TransactionType>(initialType);
  const [scope, setScope] = useState<TransactionScope>(initialScope);
  const [category, setCategory] = useState(CATEGORIES[0].name);
  const [frequency, setFrequency] = useState<FrequencyType>(FrequencyType.MONTHLY);
  const [nature, setNature] = useState<ExpenseNature>(ExpenseNature.ROUTINE);

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || !amount) return;

    onAdd({
      description,
      amount: parseFloat(amount),
      date,
      category,
      frequency,
      nature,
      type,
      scope
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4 z-50">
      <div className="bg-white rounded-2xl w-full max-w-md p-6 shadow-2xl overflow-y-auto max-h-[90vh]">
        <h2 className="text-2xl font-bold mb-6 text-slate-800">Novo Lançamento</h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="flex p-1 bg-slate-100 rounded-xl mb-4">
            {Object.values(TransactionType).map((t) => (
              <button
                key={t}
                type="button"
                onClick={() => setType(t)}
                className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${
                  type === t ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                {t}
              </button>
            ))}
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Âmbito (Escopo)</label>
            <div className="flex p-1 bg-slate-50 rounded-lg border border-slate-100">
              {Object.values(TransactionScope).map((s) => (
                <button
                  key={s}
                  type="button"
                  onClick={() => setScope(s)}
                  className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${
                    scope === s ? 'bg-white text-slate-800 shadow-sm border border-slate-200' : 'text-slate-400 hover:text-slate-600'
                  }`}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Descrição</label>
            <input
              type="text"
              required
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              placeholder="Ex: Aluguel, Salário, CDB..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Valor (R$)</label>
              <input
                type="number"
                step="0.01"
                required
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="0,00"
                value={amount}
                onChange={(e) => setAmount(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Data</label>
              <input
                type="date"
                required
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                value={date}
                onChange={(e) => setDate(e.target.value)}
              />
            </div>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Categoria</label>
            <select
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
              value={category}
              onChange={(e) => setCategory(e.target.value)}
            >
              {CATEGORIES.map(cat => (
                <option key={cat.name} value={cat.name}>{cat.name}</option>
              ))}
            </select>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Frequência</label>
              <select
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                value={frequency}
                onChange={(e) => setFrequency(e.target.value as FrequencyType)}
              >
                <option value={FrequencyType.WEEKLY}>Semanal</option>
                <option value={FrequencyType.MONTHLY}>Mensal</option>
                <option value={FrequencyType.ANNUAL}>Anual</option>
                <option value={FrequencyType.ONE_TIME}>Único</option>
              </select>
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Natureza</label>
              <select
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                value={nature}
                onChange={(e) => setNature(e.target.value as ExpenseNature)}
              >
                <option value={ExpenseNature.ROUTINE}>Rotineiro</option>
                <option value={ExpenseNature.EVENTUAL}>Eventual</option>
              </select>
            </div>
          </div>

          <div className="flex gap-3 pt-4">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-2 rounded-lg bg-slate-100 text-slate-600 font-medium hover:bg-slate-200 transition-colors"
            >
              Cancelar
            </button>
            <button
              type="submit"
              className="flex-1 px-4 py-2 rounded-lg bg-blue-600 text-white font-medium hover:bg-blue-700 transition-colors shadow-lg shadow-blue-200"
            >
              Salvar
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default TransactionForm;

import React, { useState, useEffect } from 'react';
import { Transaction, FrequencyType, ExpenseNature, TransactionType, ViewType, ExpenseSubTab, TransactionScope } from './types';
import { INITIAL_TRANSACTIONS, CATEGORIES } from './constants';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import { getFinancialInsights } from './services/geminiService';

const App: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('contas_lebol_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      return parsed.map((t: any) => ({ 
        ...t, 
        type: t.type || TransactionType.EXPENSE,
        scope: t.scope || TransactionScope.INDIVIDUAL 
      }));
    }
    return INITIAL_TRANSACTIONS;
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [formInitialType, setFormInitialType] = useState<TransactionType>(TransactionType.EXPENSE);
  const [formInitialScope, setFormInitialScope] = useState<TransactionScope>(TransactionScope.INDIVIDUAL);
  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [expenseSubTab, setExpenseSubTab] = useState<ExpenseSubTab>('all');
  const [aiInsights, setAiInsights] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [filter, setFilter] = useState<'all' | 'Rotineiro' | 'Eventual'>('all');

  useEffect(() => {
    localStorage.setItem('contas_lebol_data', JSON.stringify(transactions));
  }, [transactions]);

  const addTransaction = (newTx: Omit<Transaction, 'id'>) => {
    const transaction: Transaction = {
      ...newTx,
      id: Math.random().toString(36).substr(2, 9),
    };
    setTransactions(prev => [transaction, ...prev]);
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Tem certeza que deseja excluir este lançamento?')) {
      setTransactions(prev => prev.filter(t => t.id !== id));
    }
  };

  const generateInsights = async () => {
    if (transactions.length === 0) return;
    setIsAiLoading(true);
    setAiInsights(null);
    try {
      const insights = await getFinancialInsights(transactions);
      setAiInsights(insights);
    } finally {
      setIsAiLoading(false);
    }
  };

  const handleCadastrarClick = (type: TransactionType, scope: TransactionScope = TransactionScope.INDIVIDUAL) => {
    setFormInitialType(type);
    setFormInitialScope(scope);
    setIsFormOpen(true);
  };

  const getFilteredByView = () => {
    let base = transactions;

    if (currentView === 'expenses_individual') {
      base = transactions.filter(t => t.type === TransactionType.EXPENSE && t.scope === TransactionScope.INDIVIDUAL);
    } else if (currentView === 'expenses_domestic') {
      base = transactions.filter(t => t.type === TransactionType.EXPENSE && t.scope === TransactionScope.DOMESTIC);
    } else if (currentView === 'income') {
      base = transactions.filter(t => t.type === TransactionType.INCOME);
    } else if (currentView === 'investments') {
      base = transactions.filter(t => t.type === TransactionType.INVESTMENT);
    }

    if (currentView.startsWith('expenses_')) {
      switch(expenseSubTab) {
        case 'annuais': return base.filter(t => t.frequency === FrequencyType.ANNUAL);
        case 'mensais': return base.filter(t => t.frequency === FrequencyType.MONTHLY);
        case 'semanais': return base.filter(t => t.frequency === FrequencyType.WEEKLY);
        case 'eventuais': return base.filter(t => t.nature === ExpenseNature.EVENTUAL);
        default: return base;
      }
    }

    return base;
  };

  const filteredTransactions = getFilteredByView().filter(t => 
    filter === 'all' ? true : t.nature === filter
  );

  const SidebarItem = ({ id, label, icon, active, onClick }: { id: ViewType, label: string, icon: React.ReactNode, active: boolean, onClick: () => void }) => (
    <button
      onClick={onClick}
      className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-semibold transition-all mb-1 ${
        active 
          ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' 
          : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'
      }`}
    >
      {icon}
      <span className="text-sm truncate">{label}</span>
    </button>
  );

  const getViewLabel = (view: ViewType) => {
    switch(view) {
      case 'dashboard': return 'Início';
      case 'expenses_individual': return 'Despesa Individual';
      case 'expenses_domestic': return 'Despesa Doméstica';
      case 'income': return 'Remuneração';
      case 'investments': return 'Investimento';
      default: return view;
    }
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      {/* Sidebar - Desktop */}
      <aside className="hidden md:flex flex-col w-72 bg-white border-r border-slate-100 p-6 sticky top-0 h-screen overflow-y-auto">
        <div className="flex items-center gap-3 mb-10 px-2">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-blue-200">
            L
          </div>
          <div>
            <h1 className="text-lg font-bold text-slate-800 leading-tight">CONTAS LEBOL</h1>
            <p className="text-[10px] text-slate-400 font-bold tracking-widest uppercase">Finance Manager</p>
          </div>
        </div>

        <nav className="flex-1 space-y-2">
          <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-4 mb-2">Principal</div>
          <SidebarItem 
            id="dashboard" 
            label="Dashboard" 
            active={currentView === 'dashboard'} 
            onClick={() => setCurrentView('dashboard')}
            icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="7" rx="1"/><rect x="14" y="14" width="7" height="7" rx="1"/><rect x="3" y="14" width="7" height="7" rx="1"/></svg>}
          />

          <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-4 mb-2 mt-6">Gestão</div>
          <SidebarItem 
            id="expenses_individual" 
            label="Despesa Individual" 
            active={currentView === 'expenses_individual'} 
            onClick={() => setCurrentView('expenses_individual')}
            icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg>}
          />
          <SidebarItem 
            id="expenses_domestic" 
            label="Despesa Doméstica" 
            active={currentView === 'expenses_domestic'} 
            onClick={() => setCurrentView('expenses_domestic')}
            icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>}
          />
          <SidebarItem 
            id="income" 
            label="Remuneração" 
            active={currentView === 'income'} 
            onClick={() => setCurrentView('income')}
            icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"/></svg>}
          />
          <SidebarItem 
            id="investments" 
            label="Investimento" 
            active={currentView === 'investments'} 
            onClick={() => setCurrentView('investments')}
            icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>}
          />
        </nav>

        <div className="mt-auto space-y-2 pt-6 border-t border-slate-100">
           <button 
            onClick={() => handleCadastrarClick(TransactionType.EXPENSE)}
            className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white py-3 rounded-xl font-bold transition-all shadow-lg shadow-blue-100 text-xs"
          >
            <span>+</span> CADASTRAR DESPESA
          </button>
        </div>
      </aside>

      {/* Main Content */}
      <div className="flex-1 flex flex-col h-screen overflow-hidden">
        {/* Top bar for Mobile */}
        <header className="md:hidden bg-white border-b border-slate-100 p-4 flex justify-between items-center sticky top-0 z-40">
           <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-black text-sm">L</div>
            <h1 className="font-bold text-slate-800">CONTAS LEBOL</h1>
          </div>
          <button 
            onClick={() => setIsFormOpen(true)}
            className="bg-blue-600 text-white p-2 rounded-lg shadow-lg shadow-blue-100"
          >
            <svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4"/></svg>
          </button>
        </header>

        {/* Content Scrollable Area */}
        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-6xl mx-auto space-y-8 pb-24 lg:pb-8">

            {/* Header / Intro */}
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
              <div>
                <h2 className="text-3xl font-black text-slate-900 capitalize">{getViewLabel(currentView)}</h2>
                <p className="text-slate-500 font-medium mt-1">Bem-vindo ao seu painel de controle Lebol.</p>
              </div>

              <button 
                onClick={generateInsights}
                disabled={isAiLoading}
