            {currentView === 'dashboard' && <Dashboard transactions={transactions} />}

            {/* Transactions Section */}
            <section className="space-y-6">
              {/* Filter Bar */}
              <div className="flex flex-col gap-4">
                {/* Secondary Navigation for Expenses */}
                {currentView.startsWith('expenses_') && (
                  <div className="flex flex-wrap gap-2 pb-2">
                    {[
                      { id: 'all', label: 'Todas' },
                      { id: 'annuais', label: 'Anuais' },
                      { id: 'mensais', label: 'Mensais' },
                      { id: 'semanais', label: 'Semanais' },
                      { id: 'eventuais', label: 'Eventuais' }
                    ].map((tab) => (
                      <button
