                                {tx.nature}
                              </span>
                          </td>
                          <td className="px-6 py-4 text-right">
                            <span className={`text-sm font-black ${
                                tx.type === TransactionType.INCOME ? 'text-emerald-600' :
                                tx.type === TransactionType.INVESTMENT ? 'text-blue-600' : 'text-slate-900'
                              }`}>
                              {tx.type === TransactionType.INCOME ? '+' : '-'} R$ {tx.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                            </span>
                          </td>
                          <td className="px-6 py-4 text-center">
                            <button 
                              onClick={() => deleteTransaction(tx.id)}
                              className="text-slate-200 group-hover:text-red-400 transition-colors p-2 rounded-lg hover:bg-red-50"
                            >
                              <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                            </button>
                          </td>
