                      )) : (
                        <tr>
                          <td colSpan={6} className="px-6 py-16 text-center">
                             <div className="flex flex-col items-center gap-3 text-slate-300">
                                <svg width="48" height="48" fill="none" stroke="currentColor" strokeWidth="1" viewBox="0 0 24 24"><path d="M12 8v4m0 4h.01M21 12a9 9 0 11-18 0 9 9 0 0118 0z"/></svg>
                                <span className="font-medium">Nada por aqui ainda.</span>
                             </div>
                          </td>
                        </tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </section>
          </div>
        </main>
      </div>

      {/* Navigation Mobile - Fixed Bottom */}
      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 px-6 py-3 flex justify-between items-around z-40 overflow-x-auto">
