  EVENTUAL = 'Eventual'
}

export enum TransactionType {
  EXPENSE = 'Despesa',
  INCOME = 'Remuneração',
  INVESTMENT = 'Investimento'
}

export enum TransactionScope {
  INDIVIDUAL = 'Individual',
  DOMESTIC = 'Doméstica'
}

export enum ExpenseCategory {
  IMPOSTO = 'Imposto',
  MULTA = 'Multa',
  TAXA = 'Taxa',
  CARTAO = 'Cartão',
  RESTAURANTE = 'Restaurante',
  LANCHONETE = 'Lanchonete',
  HAPPY_HOUR = 'Happy Hour',
  PRESENTE = 'Presente',
  DIARISTA = 'Diarista',
  ENERGIA = 'Energia Elétrica',
  AGUA = 'Água',
  GAS = 'Gás',
  ESCOLA = 'Escola',
  CURSO = 'Curso',
  PSICOLOGA = 'Psicóloga',
  PLANO_SAUDE = 'Plano Saúde',
  MANUTENCAO_VEICULO = 'Manutenção Veículo',
  OUTROS = 'Outros'
}

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  vencimento: string; // Renamed from date
  pagamento: string;   // Added field
  category: ExpenseCategory | string;
  parcela: string;
  totalParcelas: string;
  nature: ExpenseNature;
  type: TransactionType;
  scope: TransactionScope;
}

export interface CategorySummary {
  name: string;
  value: number;
  color: string;
}

export type ViewType = 'dashboard' | 'expenses_individual' | 'expenses_domestic' | 'income' | 'investments';
export type ExpenseSubTab = 'all' | 'annuais' | 'mensais' | 'semanais' | 'eventuais';

import React, { useState } from 'react';
import { ExpenseNature, Transaction, TransactionType, TransactionScope, ExpenseCategory } from '../types';

interface TransactionFormProps {
  onAdd: (transaction: Omit<Transaction, 'id'>) => void;
  onClose: () => void;
  initialType?: TransactionType;
  initialScope?: TransactionScope;
  initialNature?: ExpenseNature;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ 
  onAdd, 
  onClose, 
  initialType = TransactionType.EXPENSE,
  initialScope = TransactionScope.INDIVIDUAL,
  initialNature = ExpenseNature.ROUTINE
}) => {
  const [description, setDescription] = useState('');
  const [amountDisplay, setAmountDisplay] = useState('0,00');
  const [amount, setAmount] = useState<number>(0);
  const [vencimento, setVencimento] = useState(new Date().toISOString().split('T')[0]);
  const [pagamento, setPagamento] = useState(new Date().toISOString().split('T')[0]);
  const [type, setType] = useState<TransactionType>(initialType);
  const [scope, setScope] = useState<TransactionScope>(initialScope);
  const [category, setCategory] = useState<ExpenseCategory | string>(type === TransactionType.EXPENSE ? ExpenseCategory.OUTROS : '');
  const [parcela, setParcela] = useState('');
  const [totalParcelas, setTotalParcelas] = useState('');
  const [nature, setNature] = useState<ExpenseNature>(initialNature);

  const handleAmountChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    let value = e.target.value.replace(/\D/g, '');
    if (value === '') value = '0';
    const numericValue = parseInt(value, 10) / 100;
    setAmount(numericValue);

    setAmountDisplay(
      new Intl.NumberFormat('pt-BR', {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
      }).format(numericValue)
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || amount <= 0) return;

    onAdd({
      description,
      amount,
      vencimento,
      pagamento,
      category: type === TransactionType.EXPENSE ? category : (category || 'Remuneração'),
      parcela,
      totalParcelas,
      nature,
      type,
      scope
    });
    onClose();
  };

  return (
