        <div className="fixed inset-0 bg-black/60 backdrop-blur-md flex items-center justify-center p-4 z-[60]">
          <div className="bg-white rounded-[2.5rem] w-full max-w-lg p-8 shadow-2xl space-y-8">
            {selectionStep === 1 ? (
              <>
                <div className="text-center space-y-2">
                  <h2 className="text-2xl font-black text-slate-800">Qual o âmbito da despesa?</h2>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => handleScopeSelected(TransactionScope.INDIVIDUAL)} className="flex flex-col items-center gap-4 p-6 rounded-[2rem] border-2 border-slate-100 hover:border-blue-500 hover:bg-blue-50 transition-all">
                    <div className="w-16 h-16 bg-blue-100 rounded-2xl flex items-center justify-center text-blue-600 font-bold">I</div>
                    <span className="font-bold">Individual</span>
                  </button>
                  <button onClick={() => handleScopeSelected(TransactionScope.DOMESTIC)} className="flex flex-col items-center gap-4 p-6 rounded-[2rem] border-2 border-slate-100 hover:border-indigo-500 hover:bg-indigo-50 transition-all">
                    <div className="w-16 h-16 bg-indigo-100 rounded-2xl flex items-center justify-center text-indigo-600 font-bold">D</div>
                    <span className="font-bold">Doméstica</span>
                  </button>
                </div>
              </>
            ) : (
              <>
                <div className="text-center space-y-2">
                  <h2 className="text-2xl font-black text-slate-800">Qual a natureza?</h2>
                </div>
                <div className="grid grid-cols-2 gap-3">
                  <button onClick={() => handleNatureSelected(ExpenseNature.ROUTINE)} className="p-5 rounded-3xl border-2 border-slate-50 hover:border-blue-500 bg-slate-50 font-bold">🗓️ Rotineiro</button>
                  <button onClick={() => handleNatureSelected(ExpenseNature.EVENTUAL)} className="p-5 rounded-3xl border-2 border-slate-50 hover:border-blue-500 bg-slate-50 font-bold">✨ Eventual</button>
                </div>
              </>
            )}
            <button onClick={() => setIsScopeSelectionOpen(false)} className="w-full py-3 text-sm font-bold text-slate-400 uppercase tracking-widest border-t border-slate-50">Cancelar</button>
          </div>
        </div>
      )}

      {isFormOpen && (
        <TransactionForm initialType={formInitialType} initialScope={formInitialScope} initialNature={formInitialNature} onAdd={addTransaction} onClose={() => setIsFormOpen(false)} />
      )}
    </div>
  );
};

