import React, { useState, useEffect } from 'react';
import { Transaction, ExpenseNature, TransactionType, ViewType, ExpenseSubTab, TransactionScope } from './types';
import { INITIAL_TRANSACTIONS } from './constants';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import { getFinancialInsights } from './services/geminiService';

const App: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('contas_lebol_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      return parsed.map((t: any) => ({ 
        ...t, 
        type: t.type || TransactionType.EXPENSE,
        scope: t.scope || TransactionScope.INDIVIDUAL 
      }));
    }
    return INITIAL_TRANSACTIONS;
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [isScopeSelectionOpen, setIsScopeSelectionOpen] = useState(false);
  const [selectionStep, setSelectionStep] = useState<1 | 2>(1);
  const [tempSelectedScope, setTempSelectedScope] = useState<TransactionScope>(TransactionScope.INDIVIDUAL);

  const [formInitialType, setFormInitialType] = useState<TransactionType>(TransactionType.EXPENSE);
  const [formInitialScope, setFormInitialScope] = useState<TransactionScope>(TransactionScope.INDIVIDUAL);
  const [formInitialNature, setFormInitialNature] = useState<ExpenseNature>(ExpenseNature.EVENTUAL);

  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [expenseSubTab, setExpenseSubTab] = useState<ExpenseSubTab>('all');
  const [aiInsights, setAiInsights] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [filter, setFilter] = useState<'all' | 'Rotineiro' | 'Eventual'>('all');

  useEffect(() => {
    localStorage.setItem('contas_lebol_data', JSON.stringify(transactions));
  }, [transactions]);

  const saveTransaction = (txData: Omit<Transaction, 'id'> & { id?: string }) => {
    if (txData.id) {
      // Update existing
      setTransactions(prev => prev.map(t => t.id === txData.id ? (txData as Transaction) : t));
    } else {
      // Add new
      const transaction: Transaction = {
        ...txData,
        id: Math.random().toString(36).substr(2, 9),
      } as Transaction;
      setTransactions(prev => [transaction, ...prev]);
    }
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Tem certeza que deseja excluir este lançamento?')) {
      setTransactions(prev => prev.filter(t => t.id !== id));
    }
  };

  const handleEditClick = (tx: Transaction) => {
    setEditingTransaction(tx);
    setIsFormOpen(true);
  };

  const generateInsights = async () => {
    if (transactions.length === 0) return;
    setIsAiLoading(true);
    setAiInsights(null);
    try {
      const insights = await getFinancialInsights(transactions);
      setAiInsights(insights);
    } finally {
      setIsAiLoading(false);
    }
  };

  const openExpenseWizard = () => {
    setEditingTransaction(null);
    setSelectionStep(1);
    setIsScopeSelectionOpen(true);
  };

  const handleScopeSelected = (scope: TransactionScope) => {
    setTempSelectedScope(scope);
    setSelectionStep(2);
  };

  const handleNatureSelected = (nature: ExpenseNature) => {
    setFormInitialType(TransactionType.EXPENSE);
    setFormInitialScope(tempSelectedScope);
    setFormInitialNature(nature);

    setIsScopeSelectionOpen(false);
    setIsFormOpen(true);
  };

  const getFilteredByView = () => {
    let base = transactions;

    if (currentView === 'expenses_individual') {
      base = transactions.filter(t => t.type === TransactionType.EXPENSE && t.scope === TransactionScope.INDIVIDUAL);
    } else if (currentView === 'expenses_domestic') {
      base = transactions.filter(t => t.type === TransactionType.EXPENSE && t.scope === TransactionScope.DOMESTIC);
    } else if (currentView === 'income') {
      base = transactions.filter(t => t.type === TransactionType.INCOME);
    } else if (currentView === 'investments') {
      base = transactions.filter(t => t.type === TransactionType.INVESTMENT);
    }

    if (currentView.startsWith('expenses_')) {
      switch(expenseSubTab) {
        case 'eventuais': return base.filter(t => t.nature === ExpenseNature.EVENTUAL);
        default: return base;
      }
    }

    return base;
  };

  const filteredTransactions = getFilteredByView().filter(t => 
    filter === 'all' ? true : t.nature === filter
  );

  const SidebarItem = ({ id, label, icon, active, onClick }: { id: ViewType, label: string, icon: React.ReactNode, active: boolean, onClick: () => void }) => (
    <button
      onClick={onClick}
      className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-semibold transition-all mb-1 ${
        active 
          ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' 
          : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'
      }`}
    >
      {icon}
      <span className="text-sm truncate">{label}</span>
    </button>
  );

  const getViewLabel = (view: ViewType) => {
    switch(view) {
      case 'dashboard': return 'Início';
      case 'expenses_individual': return 'Despesa Individual';
      case 'expenses_domestic': return 'Despesa Doméstica';
      case 'income': return 'Remuneração';
      case 'investments': return 'Investimento';
      default: return view;
    }
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      <aside className="hidden md:flex flex-col w-72 bg-white border-r border-slate-100 p-6 sticky top-0 h-screen overflow-y-auto">
        <div className="flex items-center gap-3 mb-10 px-2">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-blue-200">L</div>
          <div>
            <h1 className="text-lg font-bold text-slate-800 leading-tight">CONTAS LEBOL</h1>
            <p className="text-[10px] text-slate-400 font-bold tracking-widest uppercase">Finance Manager</p>
          </div>
        </div>

        <nav className="flex-1 space-y-2">
          <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-4 mb-2">Principal</div>
          <SidebarItem id="dashboard" label="Dashboard" active={currentView === 'dashboard'} onClick={() => setCurrentView('dashboard')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="7" rx="1"/><rect x="14" y="14" width="7" height="7" rx="1"/><rect x="3" y="14" width="7" height="7" rx="1"/></svg>}/>
          <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-4 mb-2 mt-6">Gestão</div>
          <SidebarItem id="expenses_individual" label="Despesa Individual" active={currentView === 'expenses_individual'} onClick={() => setCurrentView('expenses_individual')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg>}/>
          <SidebarItem id="expenses_domestic" label="Despesa Doméstica" active={currentView === 'expenses_domestic'} onClick={() => setCurrentView('expenses_domestic')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>}/>
          <SidebarItem id="income" label="Remuneração" active={currentView === 'income'} onClick={() => setCurrentView('income')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"/></svg>}/>
          <SidebarItem id="investments" label="Investimento" active={currentView === 'investments'} onClick={() => setCurrentView('investments')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>}/>
        </nav>

        <div className="mt-auto space-y-2 pt-6 border-t border-slate-100">
           <button onClick={openExpenseWizard} className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white py-3 rounded-xl font-bold transition-all shadow-lg shadow-blue-100 text-xs uppercase tracking-tighter"><span>+</span> Cadastrar Despesa</button>
        </div>
      </aside>

      <div className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="md:hidden bg-white border-b border-slate-100 p-4 flex justify-between items-center sticky top-0 z-40">
           <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-black text-sm">L</div>
            <h1 className="font-bold text-slate-800">CONTAS LEBOL</h1>
          </div>
          <button onClick={openExpenseWizard} className="bg-blue-600 text-white p-2 rounded-lg shadow-lg shadow-blue-100"><svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4"/></svg></button>
        </header>

        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-6xl mx-auto space-y-8 pb-24 lg:pb-8">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
              <div>
                <h2 className="text-3xl font-black text-slate-900 capitalize">{getViewLabel(currentView)}</h2>
                <p className="text-slate-500 font-medium mt-1">Bem-vindo ao seu painel de controle Lebol.</p>
              </div>
              <button onClick={generateInsights} disabled={isAiLoading} className={`text-sm flex items-center gap-2 font-bold px-5 py-2.5 rounded-xl border border-slate-200 bg-white shadow-sm transition-all ${isAiLoading ? 'opacity-50 cursor-not-allowed' : 'hover:bg-blue-50 hover:border-blue-200 hover:text-blue-600 active:scale-95'}`}>
                {isAiLoading ? <span className="flex items-center gap-2"><div className="w-4 h-4 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>Analisando...</span> : <>✨ Consultoria Inteligente</>}
              </button>
            </div>

            {aiInsights && (
              <div className="p-6 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-3xl text-white shadow-2xl relative overflow-hidden animate-in fade-in slide-in-from-top-4 duration-500">
                <div className="relative z-10">
                  <h3 className="text-xl font-bold mb-4 flex items-center gap-2"><span className="bg-white/20 p-1.5 rounded-lg text-xs">AI</span> Insights Lebol</h3>
                  <div className="text-blue-50 whitespace-pre-line text-sm md:text-base leading-relaxed font-medium">{aiInsights}</div>
                  <button onClick={() => setAiInsights(null)} className="mt-6 text-xs font-black text-white/50 hover:text-white uppercase tracking-widest transition-colors">Fechar</button>
                </div>
              </div>
            )}

            {currentView === 'dashboard' && <Dashboard transactions={transactions} />}

            <section className="space-y-6">
              <div className="flex flex-col gap-4">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
                  <h2 className="text-lg font-bold text-slate-800">{currentView === 'dashboard' ? 'Lançamentos Recentes' : `Lista de ${getViewLabel(currentView)}`}</h2>
                  <div className="flex p-1 bg-slate-100 rounded-xl">
                    {(['all', 'Rotineiro', 'Eventual'] as const).map((f) => (
                      <button key={f} onClick={() => setFilter(f)} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${filter === f ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>{f === 'all' ? 'Todos' : f}</button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="bg-white rounded-3xl border border-slate-100 overflow-hidden shadow-sm">
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead>
                      <tr className="bg-slate-50/50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
                        <th className="px-6 py-5">Âmbito / Vencimento / Pagto</th>
                        <th className="px-6 py-5">Descrição / Parcela</th>
                        <th className="px-6 py-5">Categoria</th>
                        <th className="px-6 py-5">Natureza</th>
                        <th className="px-6 py-5 text-right">Valor</th>
                        <th className="px-6 py-5 text-center">Ações</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                      {filteredTransactions.length > 0 ? filteredTransactions.map((tx) => (
                        <tr key={tx.id} className="group hover:bg-slate-50/50 transition-colors">
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="flex items-center gap-3">
                              <div className={`w-2 h-2 rounded-full ${tx.type === TransactionType.INCOME ? 'bg-emerald-500' : tx.type === TransactionType.INVESTMENT ? 'bg-blue-500' : tx.scope === TransactionScope.DOMESTIC ? 'bg-indigo-500' : 'bg-rose-500'}`} />
                              <div className="flex flex-col">
                                <span className="text-xs font-bold text-slate-800 uppercase tracking-tighter">{tx.scope}</span>
                                <div className="flex flex-col text-[10px] font-medium text-slate-400">
                                  <span>Venc: {tx.vencimento ? new Date(tx.vencimento).toLocaleDateString('pt-BR') : '---'}</span>
                                  {tx.pagamento && <span>Pag: {new Date(tx.pagamento).toLocaleDateString('pt-BR')}</span>}
                                </div>
                              </div>
                            </div>
                          </td>
                          <td className="px-6 py-4">
                            <p className="text-sm font-bold text-slate-800">{tx.description}</p>
                            <span className="text-[10px] text-slate-400 font-bold uppercase">
                              {tx.parcela}{tx.totalParcelas ? ` / ${tx.totalParcelas}` : ''}
                            </span>
                          </td>
                          <td className="px-6 py-4">
                            <span className="text-[10px] font-black uppercase tracking-wider px-2 py-1 rounded-lg bg-blue-50 text-blue-600">
                              {tx.category}
                            </span>
                          </td>
                          <td className="px-6 py-4">
                             <div className="flex flex-col gap-1">
                               <span className={`text-[10px] font-black uppercase tracking-wider px-2.5 py-1 rounded-full text-center ${tx.nature === 'Rotineiro' ? 'bg-blue-100 text-blue-700' : 'bg-amber-50 text-amber-600'}`}>
                                  {tx.nature}
                                </span>
                                {tx.nature === 'Rotineiro' && tx.periodicity && (
                                  <span className="text-[9px] font-bold text-blue-500 uppercase text-center">{tx.periodicity}</span>
                                )}
                             </div>
                          </td>
                          <td className="px-6 py-4 text-right">
                            <span className={`text-sm font-black ${tx.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-slate-900'}`}>
                              {tx.type === TransactionType.INCOME ? '+' : '-'} R$ {tx.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}
                            </span>
                          </td>
                          <td className="px-6 py-4 text-center">
                            <div className="flex items-center justify-center gap-2">
                              <button onClick={() => handleEditClick(tx)} className="text-slate-200 group-hover:text-blue-400 transition-colors p-2 rounded-lg hover:bg-blue-50">
                                <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"/></svg>
                              </button>
                              <button onClick={() => deleteTransaction(tx.id)} className="text-slate-200 group-hover:text-red-400 transition-colors p-2 rounded-lg hover:bg-red-50">
                                <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                              </button>
                            </div>
                          </td>
                        </tr>
                      )) : (
                        <tr><td colSpan={6} className="px-6 py-16 text-center text-slate-300 font-medium">Nada por aqui ainda.</td></tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </section>
          </div>
        </main>
      </div>

      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 px-6 py-3 flex justify-between items-around z-40">
        <button onClick={() => setCurrentView('dashboard')} className={`p-2 ${currentView === 'dashboard' ? 'text-blue-600' : 'text-slate-400'}`}><svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="7" rx="1"/><rect x="14" y="14" width="7" height="7" rx="1"/><rect x="3" y="14" width="7" height="7" rx="1"/></svg></button>
        <button onClick={() => setCurrentView('expenses_individual')} className={`p-2 ${currentView === 'expenses_individual' ? 'text-blue-600' : 'text-slate-400'}`}><svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg></button>
        <button onClick={openExpenseWizard} className="w-14 h-14 -mt-8 bg-blue-600 text-white rounded-2xl flex items-center justify-center text-3xl shadow-xl shadow-blue-300">+</button>
        <button onClick={() => setCurrentView('expenses_domestic')} className={`p-2 ${currentView === 'expenses_domestic' ? 'text-blue-600' : 'text-slate-400'}`}><svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg></button>
        <button onClick={() => setCurrentView('income')} className={`p-2 ${currentView === 'income' ? 'text-blue-600' : 'text-slate-400'}`}><svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"/></svg></button>
      </nav>

      {isScopeSelectionOpen && (
        <div className="fixed inset-0 bg-black/60 backdrop-blur-md flex items-center justify-center p-4 z-[60]">
          <div className="bg-white rounded-[2.5rem] w-full max-w-lg p-8 shadow-2xl space-y-8">
            {selectionStep === 1 ? (
              <>
                <div className="text-center space-y-2">
                  <h2 className="text-2xl font-black text-slate-800">Qual o âmbito da despesa?</h2>
                </div>
                <div className="grid grid-cols-2 gap-4">
                  <button onClick={() => handleScopeSelected(TransactionScope.INDIVIDUAL)} className="flex flex-col items-center gap-4 p-6 rounded-[2rem] border-2 border-slate-100 hover:border-blue-500 hover:bg-blue-50 transition-all">
                    <div className="w-16 h-16 bg-blue-100 rounded-2xl flex items-center justify-center text-blue-600 font-bold">I</div>
                    <span className="font-bold">Individual</span>
                  </button>
                  <button onClick={() => handleScopeSelected(TransactionScope.DOMESTIC)} className="flex flex-col items-center gap-4 p-6 rounded-[2rem] border-2 border-slate-100 hover:border-indigo-500 hover:bg-indigo-50 transition-all">
                    <div className="w-16 h-16 bg-indigo-100 rounded-2xl flex items-center justify-center text-indigo-600 font-bold">D</div>
                    <span className="font-bold">Doméstica</span>
                  </button>
                </div>
              </>
            ) : (
              <>
                <div className="text-center space-y-2">
                  <h2 className="text-2xl font-black text-slate-800">Qual a natureza?</h2>
                </div>
                <div className="grid grid-cols-2 gap-3">
                  <button onClick={() => handleNatureSelected(ExpenseNature.ROUTINE)} className="p-5 rounded-3xl border-2 border-slate-50 hover:border-blue-500 bg-slate-50 font-bold">🗓️ Rotineiro</button>
                  <button onClick={() => handleNatureSelected(ExpenseNature.EVENTUAL)} className="p-5 rounded-3xl border-2 border-slate-50 hover:border-blue-500 bg-slate-50 font-bold">✨ Eventual</button>
                </div>
              </>
            )}
            <button onClick={() => setIsScopeSelectionOpen(false)} className="w-full py-3 text-sm font-bold text-slate-400 uppercase tracking-widest border-t border-slate-50">Cancelar</button>
          </div>
        </div>
      )}

      {isFormOpen && (
        <TransactionForm 
          initialType={formInitialType} 
          initialScope={formInitialScope} 
          initialNature={formInitialNature} 
          onSave={saveTransaction} 
          onClose={() => {
            setIsFormOpen(false);
            setEditingTransaction(null);
          }} 
          editingTransaction={editingTransaction}
        />
      )}
    </div>
  );
};

export default App;

import React, { useState, useEffect } from 'react';
import { ExpenseNature, Transaction, TransactionType, TransactionScope, ExpenseCategory, PeriodicityType } from '../types';

interface TransactionFormProps {
  onSave: (transaction: Omit<Transaction, 'id'> & { id?: string }) => void;
  onClose: () => void;
  initialType?: TransactionType;
  initialScope?: TransactionScope;
  initialNature?: ExpenseNature;
  editingTransaction?: Transaction | null;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ 
  onSave, 
  onClose, 
  initialType = TransactionType.EXPENSE,
  initialScope = TransactionScope.INDIVIDUAL,
  initialNature = ExpenseNature.EVENTUAL,
  editingTransaction = null
}) => {
  const [description, setDescription] = useState('');
  const [amountDisplay, setAmountDisplay] = useState('');
  const [amount, setAmount] = useState<number>(0);
  const [vencimento, setVencimento] = useState('');
  const [pagamento, setPagamento] = useState('');
  const [type, setType] = useState<TransactionType>(initialType);
  const [scope, setScope] = useState<TransactionScope>(initialScope);
  const [category, setCategory] = useState<ExpenseCategory | string>('');
  const [parcela, setParcela] = useState('');
  const [totalParcelas, setTotalParcelas] = useState('');
  const [nature, setNature] = useState<ExpenseNature>(initialNature);
  const [periodicity, setPeriodicity] = useState<PeriodicityType>(PeriodicityType.NONE);

  useEffect(() => {
    if (editingTransaction) {
      setDescription(editingTransaction.description);
      setAmount(editingTransaction.amount);
      setAmountDisplay(
        new Intl.NumberFormat('pt-BR', {
          minimumFractionDigits: 2,
          maximumFractionDigits: 2,
        }).format(editingTransaction.amount)
      );
      setVencimento(editingTransaction.vencimento);
      setPagamento(editingTransaction.pagamento);
      setType(editingTransaction.type);
      setScope(editingTransaction.scope);
      setCategory(editingTransaction.category);
      setParcela(editingTransaction.parcela);
      setTotalParcelas(editingTransaction.totalParcelas);
      setNature(editingTransaction.nature);
      setPeriodicity(editingTransaction.periodicity || PeriodicityType.NONE);
    }
  }, [editingTransaction]);

  const handleAmountChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    let value = e.target.value.replace(/\D/g, '');
    if (value === '') {
      setAmount(0);
      setAmountDisplay('');
      return;
    }
    const numericValue = parseInt(value, 10) / 100;
    setAmount(numericValue);

    setAmountDisplay(
      new Intl.NumberFormat('pt-BR', {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
      }).format(numericValue)
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();
    if (!description || amount <= 0 || !vencimento || !category) {
      alert("Por favor, preencha todos os campos obrigatórios (Descrição, Valor, Vencimento e Categoria).");
      return;
    }

    onSave({
      id: editingTransaction?.id,
      description,
      amount,
      vencimento,
      pagamento,
      category: type === TransactionType.EXPENSE ? category : (category || 'Remuneração'),
      parcela,
      totalParcelas,
      nature,
      periodicity: nature === ExpenseNature.ROUTINE ? periodicity : PeriodicityType.NONE,
      type,
      scope
    });
    onClose();
  };

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4 z-50">
      <div className="bg-white rounded-2xl w-full max-w-md p-6 shadow-2xl overflow-y-auto max-h-[90vh]">
        <h2 className="text-2xl font-bold mb-6 text-slate-800">
          {editingTransaction ? 'Editar Lançamento' : 'Novo Lançamento'}
        </h2>
        <form onSubmit={handleSubmit} className="space-y-4">
          <div className="flex p-1 bg-slate-100 rounded-xl mb-4">
            {Object.values(TransactionType).map((t) => (
              <button
                key={t}
                type="button"
                onClick={() => setType(t)}
                className={`flex-1 py-2 text-xs font-bold rounded-lg transition-all ${
                  type === t ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'
                }`}
              >
                {t}
              </button>
            ))}
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Âmbito (Escopo)</label>
            <div className="flex p-1 bg-slate-50 rounded-lg border border-slate-100">
              {Object.values(TransactionScope).map((s) => (
                <button
                  key={s}
                  type="button"
                  onClick={() => setScope(s)}
                  className={`flex-1 py-1.5 text-xs font-bold rounded-md transition-all ${
                    scope === s ? 'bg-white text-slate-800 shadow-sm border border-slate-200' : 'text-slate-400 hover:text-slate-600'
                  }`}
                >
                  {s}
                </button>
              ))}
            </div>
          </div>

          {type === TransactionType.EXPENSE && (
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Categoria</label>
              <select
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                value={category}
                onChange={(e) => setCategory(e.target.value)}
                required
              >
                <option value="" disabled>Selecione uma categoria</option>
                {Object.values(ExpenseCategory).map(g => (
                  <option key={g} value={g}>{g.toUpperCase()}</option>
                ))}
              </select>
            </div>
          )}

          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Descrição</label>
            <input
              type="text"
              required
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              placeholder="Ex: Aluguel, Salário, CDB..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-1 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Natureza</label>
              <select
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                value={nature}
                onChange={(e) => setNature(e.target.value as ExpenseNature)}
              >
                <option value={ExpenseNature.EVENTUAL}>Eventual</option>
                <option value={ExpenseNature.ROUTINE}>Rotineiro</option>
              </select>
            </div>

            {nature === ExpenseNature.ROUTINE && (
              <div className="animate-in fade-in slide-in-from-top-2 duration-300">
                <label className="block text-sm font-medium text-slate-600 mb-1">Frequência da Rotina</label>
                <select
                  className="w-full px-4 py-2 rounded-lg border border-blue-200 bg-blue-50/30 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={periodicity}
                  onChange={(e) => setPeriodicity(e.target.value as PeriodicityType)}
                  required
                >
                  <option value="" disabled>Escolha a periodicidade</option>
                  <option value={PeriodicityType.WEEKLY}>Semanal</option>
                  <option value={PeriodicityType.MONTHLY}>Mensal</option>
                  <option value={PeriodicityType.ANNUAL}>Anual</option>
                </select>
              </div>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Valor (R$)</label>
            <input
              type="text"
              required
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
              placeholder="0,00"
              value={amountDisplay}
              onChange={handleAmountChange}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Vencimento</label>
              <input
                type="date"
                required
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                value={vencimento}
                onChange={(e) => setVencimento(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1 text-[11px] leading-tight">Pagamento/Agendamento</label>
              <input
                type="date"
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                value={pagamento}
                onChange={(e) => setPagamento(e.target.value)}
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Parcela</label>
              <input
                type="text"
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Ex: 1, 6, etc."
                value={parcela}
                onChange={(e) => setParcela(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Total de Parcelas</label>
              <input
                type="text"
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Ex: 12, 24, etc."
                value={totalParcelas}
                onChange={(e) => setTotalParcelas(e.target.value)}
              />
            </div>
          </div>

          <div className="flex gap-3 pt-4">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-2 rounded-lg bg-slate-100 text-slate-600 font-medium hover:bg-slate-200 transition-colors"
            >
              Cancelar
            </button>
            <button
              type="submit"
              className="flex-1 px-4 py-2 rounded-lg bg-blue-600 text-white font-medium hover:bg-blue-700 transition-colors shadow-lg shadow-blue-200"
            >
              {editingTransaction ? 'Atualizar' : 'Salvar'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

export default TransactionForm;

import React, { useState, useEffect } from 'react';
import { Transaction, ExpenseNature, TransactionType, ViewType, ExpenseSubTab, TransactionScope } from './types';
import { INITIAL_TRANSACTIONS } from './constants';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import { getFinancialInsights } from './services/geminiService';

const App: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('contas_lebol_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      return parsed.map((t: any) => ({ 
        ...t, 
        type: t.type || TransactionType.EXPENSE,
        scope: t.scope || TransactionScope.INDIVIDUAL 
      }));
    }
    return INITIAL_TRANSACTIONS;
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [isScopeSelectionOpen, setIsScopeSelectionOpen] = useState(false);
  const [tempSelectedScope, setTempSelectedScope] = useState<TransactionScope>(TransactionScope.INDIVIDUAL);

  const [formInitialType, setFormInitialType] = useState<TransactionType>(TransactionType.EXPENSE);
  const [formInitialScope, setFormInitialScope] = useState<TransactionScope>(TransactionScope.INDIVIDUAL);
  const [formInitialNature, setFormInitialNature] = useState<ExpenseNature>(ExpenseNature.EVENTUAL);

  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [expenseSubTab, setExpenseSubTab] = useState<ExpenseSubTab>('all');
  const [aiInsights, setAiInsights] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [filter, setFilter] = useState<'all' | 'Rotineiro' | 'Eventual'>('all');

  useEffect(() => {
    localStorage.setItem('contas_lebol_data', JSON.stringify(transactions));
  }, [transactions]);

  const saveTransaction = (txData: Omit<Transaction, 'id'> & { id?: string }) => {
    if (txData.id) {
      // Update existing
      setTransactions(prev => prev.map(t => t.id === txData.id ? (txData as Transaction) : t));
    } else {
      // Add new
      const transaction: Transaction = {
        ...txData,
        id: Math.random().toString(36).substr(2, 9),
      } as Transaction;
      setTransactions(prev => [transaction, ...prev]);
    }
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Tem certeza que deseja excluir este lançamento?')) {
      setTransactions(prev => prev.filter(t => t.id !== id));
    }
  };

  const handleEditClick = (tx: Transaction) => {
    setEditingTransaction(tx);
    setIsFormOpen(true);
  };

  const generateInsights = async () => {
    if (transactions.length === 0) return;
    setIsAiLoading(true);
    setAiInsights(null);
    try {
      const insights = await getFinancialInsights(transactions);
      setAiInsights(insights);
    } finally {
      setIsAiLoading(false);
    }
  };

  const openExpenseWizard = () => {
    setEditingTransaction(null);
    setIsScopeSelectionOpen(true);
  };

  const handleScopeSelected = (scope: TransactionScope) => {
    setFormInitialType(TransactionType.EXPENSE);
    setFormInitialScope(scope);
    setFormInitialNature(ExpenseNature.EVENTUAL); // Default to Eventual, can be changed in form

    setIsScopeSelectionOpen(false);
    setIsFormOpen(true);
  };

  const getFilteredByView = () => {
    let base = transactions;

    if (currentView === 'expenses_individual') {
      base = transactions.filter(t => t.type === TransactionType.EXPENSE && t.scope === TransactionScope.INDIVIDUAL);
    } else if (currentView === 'expenses_domestic') {
      base = transactions.filter(t => t.type === TransactionType.EXPENSE && t.scope === TransactionScope.DOMESTIC);
    } else if (currentView === 'income') {
      base = transactions.filter(t => t.type === TransactionType.INCOME);
    } else if (currentView === 'investments') {
      base = transactions.filter(t => t.type === TransactionType.INVESTMENT);
    }

    if (currentView.startsWith('expenses_')) {
      switch(expenseSubTab) {
        case 'eventuais': return base.filter(t => t.nature === ExpenseNature.EVENTUAL);
        default: return base;
      }
    }

    return base;
  };

  const filteredTransactions = getFilteredByView().filter(t => 
    filter === 'all' ? true : t.nature === filter
  );

  const SidebarItem = ({ id, label, icon, active, onClick }: { id: ViewType, label: string, icon: React.ReactNode, active: boolean, onClick: () => void }) => (
    <button
      onClick={onClick}
      className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-semibold transition-all mb-1 ${
        active 
          ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' 
          : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'
      }`}
    >
      {icon}
      <span className="text-sm truncate">{label}</span>
    </button>
  );

  const getViewLabel = (view: ViewType) => {
    switch(view) {
      case 'dashboard': return 'Início';
      case 'expenses_individual': return 'Despesa Individual';
      case 'expenses_domestic': return 'Despesa Doméstica';
      case 'income': return 'Remuneração';
      case 'investments': return 'Investimento';
      default: return view;
    }
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      <aside className="hidden md:flex flex-col w-72 bg-white border-r border-slate-100 p-6 sticky top-0 h-screen overflow-y-auto">
        <div className="flex items-center gap-3 mb-10 px-2">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-blue-200">L</div>
          <div>
            <h1 className="text-lg font-bold text-slate-800 leading-tight">CONTAS LEBOL</h1>
            <p className="text-[10px] text-slate-400 font-bold tracking-widest uppercase">Finance Manager</p>
          </div>
        </div>

        <nav className="flex-1 space-y-2">
          <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-4 mb-2">Principal</div>
          <SidebarItem id="dashboard" label="Dashboard" active={currentView === 'dashboard'} onClick={() => setCurrentView('dashboard')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="7" rx="1"/><rect x="14" y="14" width="7" height="7" rx="1"/><rect x="3" y="14" width="7" height="7" rx="1"/></svg>}/>
          <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-4 mb-2 mt-6">Gestão</div>
          <SidebarItem id="expenses_individual" label="Despesa Individual" active={currentView === 'expenses_individual'} onClick={() => setCurrentView('expenses_individual')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg>}/>
          <SidebarItem id="expenses_domestic" label="Despesa Doméstica" active={currentView === 'expenses_domestic'} onClick={() => setCurrentView('expenses_domestic')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>}/>
          <SidebarItem id="income" label="Remuneração" active={currentView === 'income'} onClick={() => setCurrentView('income')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"/></svg>}/>
          <SidebarItem id="investments" label="Investimento" active={currentView === 'investments'} onClick={() => setCurrentView('investments')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>}/>
        </nav>

        <div className="mt-auto space-y-2 pt-6 border-t border-slate-100">
           <button onClick={openExpenseWizard} className="w-full flex items-center justify-center gap-2 bg-blue-600 hover:bg-blue-700 text-white py-3 rounded-xl font-bold transition-all shadow-lg shadow-blue-100 text-xs uppercase tracking-tighter"><span>+</span> Cadastrar Despesa</button>
        </div>
      </aside>

      <div className="flex-1 flex flex-col h-screen overflow-hidden">
        <header className="md:hidden bg-white border-b border-slate-100 p-4 flex justify-between items-center sticky top-0 z-40">
           <div className="flex items-center gap-2">
            <div className="w-8 h-8 bg-blue-600 rounded-lg flex items-center justify-center text-white font-black text-sm">L</div>
            <h1 className="font-bold text-slate-800">CONTAS LEBOL</h1>
          </div>
          <button onClick={openExpenseWizard} className="bg-blue-600 text-white p-2 rounded-lg shadow-lg shadow-blue-100"><svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4"/></svg></button>
        </header>

        <main className="flex-1 overflow-y-auto p-4 md:p-8">
          <div className="max-w-6xl mx-auto space-y-8 pb-24 lg:pb-8">
            <div className="flex flex-col md:flex-row md:items-end justify-between gap-4">
              <div>
                <h2 className="text-3xl font-black text-slate-900 capitalize">{getViewLabel(currentView)}</h2>
                <p className="text-slate-500 font-medium mt-1">Bem-vindo ao seu painel de controle Lebol.</p>
              </div>
              <button onClick={generateInsights} disabled={isAiLoading} className={`text-sm flex items-center gap-2 font-bold px-5 py-2.5 rounded-xl border border-slate-200 bg-white shadow-sm transition-all ${isAiLoading ? 'opacity-50 cursor-not-allowed' : 'hover:bg-blue-50 hover:border-blue-200 hover:text-blue-600 active:scale-95'}`}>
                {isAiLoading ? <span className="flex items-center gap-2"><div className="w-4 h-4 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>Analisando...</span> : <>✨ Consultoria Inteligente</>}
              </button>
