export default App;

import React, { useState, useEffect } from 'react';
import { Transaction, ExpenseNature, TransactionType, ViewType, ExpenseSubTab, TransactionScope } from './types';
import { INITIAL_TRANSACTIONS } from './constants';
import Dashboard from './components/Dashboard';
import TransactionForm from './components/TransactionForm';
import { getFinancialInsights } from './services/geminiService';

const addMonths = (dateStr: string, months: number) => {
  if (!dateStr) return '';
  const [year, month, day] = dateStr.split('-').map(Number);
  const date = new Date(year, month - 1 + months, day);
  // Check if we overflowed the month (e.g. Jan 31 -> Feb 28/29)
  if (date.getDate() !== day) {
    date.setDate(0); // Go back to last day of intended month
  }
  const y = date.getFullYear();
  const m = String(date.getMonth() + 1).padStart(2, '0');
  const d = String(date.getDate()).padStart(2, '0');
  return `${y}-${m}-${d}`;
};

const App: React.FC = () => {
  const [transactions, setTransactions] = useState<Transaction[]>(() => {
    const saved = localStorage.getItem('contas_lebol_data');
    if (saved) {
      const parsed = JSON.parse(saved);
      return parsed.map((t: any) => ({ 
        ...t, 
        type: t.type || TransactionType.EXPENSE,
        scope: t.scope || TransactionScope.INDIVIDUAL 
      }));
    }
    return INITIAL_TRANSACTIONS;
  });

  const [isFormOpen, setIsFormOpen] = useState(false);
  const [editingTransaction, setEditingTransaction] = useState<Transaction | null>(null);
  const [isScopeSelectionOpen, setIsScopeSelectionOpen] = useState(false);

  const [formInitialType, setFormInitialType] = useState<TransactionType>(TransactionType.EXPENSE);
  const [formInitialScope, setFormInitialScope] = useState<TransactionScope>(TransactionScope.INDIVIDUAL);
  const [formInitialNature, setFormInitialNature] = useState<ExpenseNature>(ExpenseNature.EVENTUAL);

  const [currentView, setCurrentView] = useState<ViewType>('dashboard');
  const [expenseSubTab, setExpenseSubTab] = useState<ExpenseSubTab>('all');
  const [aiInsights, setAiInsights] = useState<string | null>(null);
  const [isAiLoading, setIsAiLoading] = useState(false);
  const [filter, setFilter] = useState<'all' | 'Rotineiro' | 'Eventual'>('all');

  useEffect(() => {
    localStorage.setItem('contas_lebol_data', JSON.stringify(transactions));
  }, [transactions]);

  const saveTransaction = (txData: Omit<Transaction, 'id'> & { id?: string, multiplicar?: boolean }) => {
    if (txData.id) {
      // Update existing
      setTransactions(prev => prev.map(t => t.id === txData.id ? (txData as Transaction) : t));
    } else {
      // Add new
      const mainTx: Transaction = {
        ...txData,
        id: Math.random().toString(36).substr(2, 9),
      } as Transaction;

      let finalTxs: Transaction[] = [mainTx];

      // Handle multiplication
      if (txData.multiplicar && txData.parcela && txData.totalParcelas) {
        const currentParcel = parseInt(txData.parcela);
        const total = parseInt(txData.totalParcelas);
        if (!isNaN(currentParcel) && !isNaN(total) && currentParcel < total) {
          for (let i = currentParcel + 1; i <= total; i++) {
            finalTxs.push({
              ...txData,
              id: Math.random().toString(36).substr(2, 9),
              parcela: i.toString(),
              vencimento: addMonths(txData.vencimento, i - currentParcel),
              pagamento: '', // Should be empty for future installments
              multiplicar: false // Reset flag for children
            } as Transaction);
          }
        }
      }

      setTransactions(prev => [...finalTxs, ...prev]);
    }
    setEditingTransaction(null);
  };

  const deleteTransaction = (id: string) => {
    if (confirm('Tem certeza que deseja excluir este lançamento?')) {
      setTransactions(prev => prev.filter(t => t.id !== id));
    }
  };

  const handleEditClick = (tx: Transaction) => {
    setEditingTransaction(tx);
    setIsFormOpen(true);
  };

  const generateInsights = async () => {
    if (transactions.length === 0) return;
    setIsAiLoading(true);
    setAiInsights(null);
    try {
      const insights = await getFinancialInsights(transactions);
      setAiInsights(insights);
    } finally {
      setIsAiLoading(false);
    }
  };

  const openExpenseWizard = () => {
    setEditingTransaction(null);
    setIsScopeSelectionOpen(true);
  };

  const handleScopeSelected = (scope: TransactionScope) => {
    setFormInitialType(TransactionType.EXPENSE);
    setFormInitialScope(scope);
    setFormInitialNature(ExpenseNature.EVENTUAL); 

    setIsScopeSelectionOpen(false);
    setIsFormOpen(true);
  };

  const getFilteredByView = () => {
    let base = transactions;

    if (currentView === 'expenses_individual') {
      base = transactions.filter(t => t.type === TransactionType.EXPENSE && t.scope === TransactionScope.INDIVIDUAL);
    } else if (currentView === 'expenses_domestic') {
      base = transactions.filter(t => t.type === TransactionType.EXPENSE && t.scope === TransactionScope.DOMESTIC);
    } else if (currentView === 'income') {
      base = transactions.filter(t => t.type === TransactionType.INCOME);
    } else if (currentView === 'investments') {
      base = transactions.filter(t => t.type === TransactionType.INVESTMENT);
    }

    if (currentView.startsWith('expenses_')) {
      switch(expenseSubTab) {
        case 'eventuais': return base.filter(t => t.nature === ExpenseNature.EVENTUAL);
        default: return base;
      }
    }

    return base;
  };

  const filteredTransactions = getFilteredByView().filter(t => 
    filter === 'all' ? true : t.nature === filter
  );

  const SidebarItem = ({ id, label, icon, active, onClick }: { id: ViewType, label: string, icon: React.ReactNode, active: boolean, onClick: () => void }) => (
    <button
      onClick={onClick}
      className={`w-full flex items-center gap-3 px-4 py-3 rounded-xl font-semibold transition-all mb-1 ${
        active 
          ? 'bg-blue-600 text-white shadow-lg shadow-blue-200' 
          : 'text-slate-500 hover:bg-slate-50 hover:text-slate-800'
      }`}
    >
      {icon}
      <span className="text-sm truncate">{label}</span>
    </button>
  );

  const getViewLabel = (view: ViewType) => {
    switch(view) {
      case 'dashboard': return 'Início';
      case 'expenses_individual': return 'Despesa Individual';
      case 'expenses_domestic': return 'Despesa Doméstica';
      case 'income': return 'Remuneração';
      case 'investments': return 'Investimento';
      default: return view;
    }
  }

  return (
    <div className="min-h-screen bg-slate-50 flex flex-col md:flex-row">
      <aside className="hidden md:flex flex-col w-72 bg-white border-r border-slate-100 p-6 sticky top-0 h-screen overflow-y-auto">
        <div className="flex items-center gap-3 mb-10 px-2">
          <div className="w-10 h-10 bg-blue-600 rounded-xl flex items-center justify-center text-white font-black text-xl shadow-lg shadow-blue-200">L</div>
          <div>
            <h1 className="text-lg font-bold text-slate-800 leading-tight">CONTAS LEBOL</h1>
            <p className="text-[10px] text-slate-400 font-bold tracking-widest uppercase">Finance Manager</p>
          </div>
        </div>

        <nav className="flex-1 space-y-2">
          <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-4 mb-2">Principal</div>
          <SidebarItem id="dashboard" label="Dashboard" active={currentView === 'dashboard'} onClick={() => setCurrentView('dashboard')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="7" rx="1"/><rect x="14" y="14" width="7" height="7" rx="1"/><rect x="3" y="14" width="7" height="7" rx="1"/></svg>}/>
          <div className="text-[10px] font-bold text-slate-400 uppercase tracking-widest px-4 mb-2 mt-6">Gestão</div>
          <SidebarItem id="expenses_individual" label="Despesa Individual" active={currentView === 'expenses_individual'} onClick={() => setCurrentView('expenses_individual')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg>}/>
          <SidebarItem id="expenses_domestic" label="Despesa Doméstica" active={currentView === 'expenses_domestic'} onClick={() => setCurrentView('expenses_domestic')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg>}/>
          <SidebarItem id="income" label="Remuneração" active={currentView === 'income'} onClick={() => setCurrentView('income')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"/></svg>}/>
          <SidebarItem id="investments" label="Investimento" active={currentView === 'investments'} onClick={() => setCurrentView('investments')} icon={<svg width="20" height="20" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M13 10V3L4 14h7v7l9-11h-7z"/></svg>}/>
