      totalParcelas,
      nature,
      periodicity: nature === ExpenseNature.ROUTINE ? periodicity : PeriodicityType.NONE,
      type,
      scope,
      multiplicar: !editingTransaction && multiplicar // Only multiply on new entries
    });
    onClose();
  };

  const showMultiplier = !editingTransaction && 
    totalParcelas && 
    parcela && 
    parseInt(totalParcelas) > parseInt(parcela);

