                  <button 
                    type="button" 
                    onClick={openIncomeForm} 
                    className="text-sm flex items-center gap-2 font-black px-5 py-2.5 rounded-xl bg-emerald-600 text-white shadow-lg shadow-emerald-100 hover:bg-emerald-700 active:scale-95 transition-all"
                  >
                    <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4"/></svg>
                    CADASTRAR REMUNERAÇÃO
                  </button>
                )}
                {currentView === 'expenses_individual' && (
                  <button 
                    type="button" 
                    onClick={openIndividualExpenseForm} 
                    className="text-sm flex items-center gap-2 font-black px-5 py-2.5 rounded-xl bg-rose-600 text-white shadow-lg shadow-rose-100 hover:bg-rose-700 active:scale-95 transition-all"
                  >
                    <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4"/></svg>
                    CADASTRAR DESPESA
                  </button>
                )}
                {currentView === 'expenses_domestic' && (
                  <button 
                    type="button" 
                    onClick={openDomesticExpenseForm} 
                    className="text-sm flex items-center gap-2 font-black px-5 py-2.5 rounded-xl bg-indigo-600 text-white shadow-lg shadow-indigo-100 hover:bg-indigo-700 active:scale-95 transition-all"
                  >
                    <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4"/></svg>
                    CADASTRAR DESPESA
                  </button>
                )}
                {currentView === 'investments' && (
                  <button 
                    type="button" 
                    onClick={openInvestmentForm} 
                    className="text-sm flex items-center gap-2 font-black px-5 py-2.5 rounded-xl bg-blue-600 text-white shadow-lg shadow-blue-100 hover:bg-blue-700 active:scale-95 transition-all"
                  >
                    <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2.5" viewBox="0 0 24 24"><path d="M12 4v16m8-8H4"/></svg>
                    CADASTRAR INVESTIMENTO
                  </button>
                )}
                <button type="button" onClick={generateInsights} disabled={isAiLoading} className={`text-sm flex items-center gap-2 font-bold px-5 py-2.5 rounded-xl border border-slate-200 bg-white shadow-sm transition-all ${isAiLoading ? 'opacity-50 cursor-not-allowed' : 'hover:bg-blue-50 hover:border-blue-200 hover:text-blue-600 active:scale-95'}`}>
                  {isAiLoading ? <span className="flex items-center gap-2"><div className="w-4 h-4 border-2 border-blue-600 border-t-transparent rounded-full animate-spin"></div>Analisando...</span> : <>✨ Consultoria Inteligente</>}
                </button>
              </div>
            </div>

            {aiInsights && (
              <div className="p-6 bg-gradient-to-br from-blue-600 to-indigo-700 rounded-3xl text-white shadow-2xl relative overflow-hidden animate-in fade-in slide-in-from-top-4 duration-500">
                <div className="relative z-10">
                  <h3 className="text-xl font-bold mb-4 flex items-center gap-2"><span className="bg-white/20 p-1.5 rounded-lg text-xs">AI</span> Insights Lebol</h3>
                  <div className="text-blue-50 whitespace-pre-line text-sm md:text-base leading-relaxed font-medium">{aiInsights}</div>
                  <button type="button" onClick={() => setAiInsights(null)} className="mt-6 text-xs font-black text-white/50 hover:text-white uppercase tracking-widest transition-colors">Fechar</button>
                </div>
              </div>
            )}

            {currentView === 'dashboard' && <Dashboard transactions={transactions} />}

            <section className="space-y-6">
              <div className="flex flex-col gap-4">
                <div className="flex flex-col md:flex-row md:items-center justify-between gap-4 bg-white p-4 rounded-2xl border border-slate-100 shadow-sm">
                  <h2 className="text-lg font-bold text-slate-800">{currentView === 'dashboard' ? 'Lançamentos Recentes' : `Lista de ${getViewLabel(currentView)}`}</h2>
                  <div className="flex p-1 bg-slate-100 rounded-xl">
                    {(['all', 'Rotineiro', 'Eventual'] as const).map((f) => (
                      <button key={f} type="button" onClick={() => setFilter(f)} className={`px-4 py-1.5 rounded-lg text-xs font-bold transition-all ${filter === f ? 'bg-white text-blue-600 shadow-sm' : 'text-slate-500 hover:text-slate-700'}`}>{f === 'all' ? 'Todos' : f}</button>
                    ))}
                  </div>
                </div>
              </div>

              <div className="bg-white rounded-3xl border border-slate-100 overflow-hidden shadow-sm">
                <div className="overflow-x-auto">
                  <table className="w-full text-left">
                    <thead>
                      <tr className="bg-slate-50/50 text-slate-400 text-[10px] font-black uppercase tracking-widest">
                        <th className="px-6 py-5">Âmbito</th>
                        <th className="px-6 py-5">Descrição / Parcela</th>
                        <th className="px-6 py-5">Categoria</th>
                        <th className="px-6 py-5">Natureza</th>
                        <th className="px-6 py-5 text-right">Valor</th>
                        <th className="px-6 py-5">Vencimento</th>
                        <th className="px-6 py-5 text-center">Ações</th>
                      </tr>
                    </thead>
                    <tbody className="divide-y divide-slate-50">
                      {filteredTransactions.length > 0 ? filteredTransactions.map((tx) => (
                        <tr key={tx.id} className="group hover:bg-slate-50/50 transition-colors">
                          <td className="px-6 py-4 whitespace-nowrap">
                            <div className="flex items-center gap-3">
                              <div className={`w-2.5 h-2.5 rounded-full ${tx.type === TransactionType.INCOME ? 'bg-emerald-500' : tx.type === TransactionType.INVESTMENT ? 'bg-blue-500' : tx.scope === TransactionScope.DOMESTIC ? 'bg-indigo-500' : 'bg-rose-500'}`} />
                              <span className="text-xs font-bold text-slate-800 uppercase tracking-tighter">{tx.scope}</span>
                            </div>
                          </td>
                          <td className="px-6 py-4">
                            <p className="text-sm font-bold text-slate-800">{tx.description}</p>
                            <span className="text-[10px] text-slate-400 font-bold uppercase">
                              {tx.parcela}{tx.totalParcelas ? ` / ${tx.totalParcelas}` : ''}
                            </span>
                          </td>
                          <td className="px-6 py-4">
                            <span className="text-[10px] font-black uppercase tracking-wider px-2 py-1 rounded-lg bg-blue-50 text-blue-600">
                              {tx.category}
                            </span>
                          </td>
                          <td className="px-6 py-4">
                             <div className="flex flex-col gap-1">
                               <span className={`text-[10px] font-black uppercase tracking-wider px-2.5 py-1 rounded-full text-center ${tx.nature === 'Rotineiro' ? 'bg-blue-100 text-blue-700' : 'bg-amber-50 text-amber-600'}`}>
                                  {tx.nature}
                                </span>
                                {tx.nature === 'Rotineiro' && tx.periodicity && (
                                  <span className="text-[9px] font-bold text-blue-500 uppercase text-center">{tx.periodicity}</span>
                                )}
                             </div>
                          </td>
                          <td className="px-6 py-4 text-right">
                            <span className={`text-sm font-black ${tx.type === TransactionType.INCOME ? 'text-emerald-600' : 'text-slate-900'}`}>
                              {tx.type === TransactionType.INCOME ? '+' : tx.type === TransactionType.INVESTMENT ? '-' : '-'} {
                                (tx.category === ExpenseCategory.CARTAO && tx.amount === 0) 
                                ? <span className="text-blue-500 italic font-medium">checar</span>
                                : `R$ ${tx.amount.toLocaleString('pt-BR', { minimumFractionDigits: 2 })}`
                              }
                            </span>
                          </td>
                          <td className="px-6 py-4">
                            <div className="flex flex-row items-center gap-2">
                              <span className={`text-sm font-bold ${tx.pagamento ? 'text-emerald-600' : 'text-rose-600'}`}>
                                {tx.vencimento ? new Date(tx.vencimento + 'T12:00:00').toLocaleDateString('pt-BR') : '---'}
                              </span>
                              {tx.pagamento && (
                                <span className="text-[9px] font-black bg-emerald-100 text-emerald-700 px-1.5 py-0.5 rounded border border-emerald-200 uppercase tracking-tighter">PG</span>
                              )}
                            </div>
                          </td>
                          <td className="px-6 py-4 text-center">
                            <div className="flex items-center justify-center gap-2">
                              <button type="button" onClick={() => handleEditClick(tx)} className="text-slate-400 hover:text-blue-500 transition-all p-2 rounded-lg hover:bg-blue-50 active:scale-90">
                                <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M11 5H6a2 2 0 00-2 2v11a2 2 0 002 2h11a2 2 0 002-2v-5m-1.414-9.414a2 2 0 112.828 2.828L11.828 15H9v-2.828l8.586-8.586z"/></svg>
                              </button>
                              <button type="button" onClick={() => deleteTransaction(tx.id)} className="text-slate-400 hover:text-red-500 transition-all p-2 rounded-lg hover:bg-red-50 active:scale-90" title="Excluir">
                                <svg width="18" height="18" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M19 7l-.867 12.142A2 2 0 0116.138 21H7.862a2 2 0 01-1.995-1.858L5 7m5 4v6m4-6v6m1-10V4a1 1 0 00-1-1h-4a1 1 0 00-1 1v3M4 7h16"/></svg>
                              </button>
                            </div>
                          </td>
                        </tr>
                      )) : (
                        <tr><td colSpan={7} className="px-6 py-16 text-center text-slate-300 font-medium">Nada por aqui ainda.</td></tr>
                      )}
                    </tbody>
                  </table>
                </div>
              </div>
            </section>
          </div>
        </main>
      </div>

      <nav className="md:hidden fixed bottom-0 left-0 right-0 bg-white border-t border-slate-100 px-6 py-3 flex justify-between items-around z-40">
        <button type="button" onClick={() => setCurrentView('dashboard')} className={`p-2 flex-1 ${currentView === 'dashboard' ? 'text-blue-600' : 'text-slate-400'}`}><div className="flex flex-col items-center gap-1"><svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><rect x="3" y="3" width="7" height="7" rx="1"/><rect x="14" y="3" width="7" height="7" rx="1"/><rect x="14" y="14" width="7" height="7" rx="1"/><rect x="3" y="14" width="7" height="7" rx="1"/></svg></div></button>
        <button type="button" onClick={() => setCurrentView('expenses_individual')} className={`p-2 flex-1 ${currentView === 'expenses_individual' ? 'text-blue-600' : 'text-slate-400'}`}><div className="flex flex-col items-center gap-1"><svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M16 7a4 4 0 11-8 0 4 4 0 018 0zM12 14a7 7 0 00-7 7h14a7 7 0 00-7-7z"/></svg></div></button>
        <button type="button" onClick={() => setCurrentView('expenses_domestic')} className={`p-2 flex-1 ${currentView === 'expenses_domestic' ? 'text-blue-600' : 'text-slate-400'}`}><div className="flex flex-col items-center gap-1"><svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M3 12l2-2m0 0l7-7 7 7M5 10v10a1 1 0 001 1h3m10-11l2 2m-2-2v10a1 1 0 01-1 1h-3m-6 0a1 1 0 001-1v-4a1 1 0 011-1h2a1 1 0 011 1v4a1 1 0 001 1m-6 0h6"/></svg></div></button>
        <button type="button" onClick={() => setCurrentView('income')} className={`p-2 flex-1 ${currentView === 'income' ? 'text-blue-600' : 'text-slate-400'}`}><div className="flex flex-col items-center gap-1"><svg width="24" height="24" fill="none" stroke="currentColor" strokeWidth="2" viewBox="0 0 24 24"><path d="M13 7h8m0 0v8m0-8l-8 8-4-4-6 6"/></svg></div></button>
      </nav>

      {isFormOpen && (
        <TransactionForm 
          initialType={formInitialType} 
          initialScope={formInitialScope} 
          initialNature={formInitialNature} 
          onSave={saveTransaction} 
          onClose={() => {
            setIsFormOpen(false);
            setEditingTransaction(null);
          }} 
          editingTransaction={editingTransaction}
        />
      )}
    </div>
  );
};

export default App;

export enum ExpenseNature {
  ROUTINE = 'Rotineiro',
  EVENTUAL = 'Eventual'
}

export enum PeriodicityType {
  ANNUAL = 'Anual',
  SEMIANNUAL = 'Semestral',
  MONTHLY = 'Mensal',
  WEEKLY = 'Semanal',
  NONE = ''
}

export enum TransactionType {
  EXPENSE = 'Despesa',
  INCOME = 'Remuneração',
  INVESTMENT = 'Investimento'
}

export enum TransactionScope {
  INDIVIDUAL = 'Individual',
  DOMESTIC = 'Doméstica'
}

export enum ExpenseCategory {
  IMPOSTO = 'Imposto',
  MULTA = 'Multa',
  TAXA = 'Taxa',
  CARTAO = 'Cartão',
  RESTAURANTE = 'Restaurante',
  LANCHONETE = 'Lanchonete',
  HAPPY_HOUR = 'Happy Hour',
  PRESENTE = 'Presente',
  DIARISTA = 'Diarista',
  ENERGIA = 'Energia Elétrica',
  AGUA = 'Água',
  GAS = 'Gás',
  ESCOLA = 'Escola',
  CURSO = 'Curso',
  PSICOLOGA = 'Psicóloga',
  PLANO_SAUDE = 'Plano Saúde',
  MANUTENCAO_VEICULO = 'Manutenção Veículo',
  OUTROS = 'Outros'
}

export enum IncomeCategory {
  SUBSIDIO = 'Subsídio',
  VOLUNTARIO = 'Voluntário',
  AUXILIO_ALIMENTACAO = 'Auxílio Alimentação',
  AUXILIO_UNIFORME = 'Auxílio Uniforme',
  DIARIAS = 'Diárias',
  AJUDA_CUSTO = 'Ajuda de Custo',
  ALUGUEL = 'Aluguel',
  OUTROS_RENDIMENTOS = 'Outros Rendimentos'
}

export interface Transaction {
  id: string;
  description: string;
  amount: number;
  vencimento: string;
  pagamento: string;
  category: ExpenseCategory | IncomeCategory | string;
  parcela: string;
  totalParcelas: string;
  nature: ExpenseNature;
  periodicity?: PeriodicityType;
  type: TransactionType;
  scope: TransactionScope;
}

export interface CategorySummary {
  name: string;
  value: number;
  color: string;
}

export type ViewType = 'dashboard' | 'expenses_individual' | 'expenses_domestic' | 'income' | 'investments';
export type ExpenseSubTab = 'all' | 'annuais' | 'mensais' | 'semanais' | 'eventuais';

import React, { useState, useEffect } from 'react';
import { ExpenseNature, Transaction, TransactionType, TransactionScope, ExpenseCategory, IncomeCategory, PeriodicityType } from '../types';

interface TransactionFormProps {
  onSave: (transaction: Omit<Transaction, 'id'> & { id?: string, multiplicar?: boolean }) => void;
  onClose: () => void;
  initialType?: TransactionType;
  initialScope?: TransactionScope;
  initialNature?: ExpenseNature;
  editingTransaction?: Transaction | null;
}

const TransactionForm: React.FC<TransactionFormProps> = ({ 
  onSave, 
  onClose, 
  initialType = TransactionType.EXPENSE,
  initialScope = TransactionScope.INDIVIDUAL,
  initialNature = ExpenseNature.EVENTUAL,
  editingTransaction = null
}) => {
  const [description, setDescription] = useState('');
  const [amountDisplay, setAmountDisplay] = useState('');
  const [amount, setAmount] = useState<number>(0);
  const [vencimento, setVencimento] = useState('');
  const [pagamento, setPagamento] = useState('');
  const [type, setType] = useState<TransactionType>(initialType);
  const [scope, setScope] = useState<TransactionScope>(initialScope);
  const [category, setCategory] = useState<string>('');
  const [parcela, setParcela] = useState('');
  const [totalParcelas, setTotalParcelas] = useState('');
  const [nature, setNature] = useState<ExpenseNature>(initialNature);
  const [periodicity, setPeriodicity] = useState<PeriodicityType>(PeriodicityType.NONE);
  const [multiplicar, setMultiplicar] = useState(false);

  useEffect(() => {
    if (editingTransaction) {
      setDescription(editingTransaction.description);
      setAmount(editingTransaction.amount);
      if (editingTransaction.amount > 0) {
        setAmountDisplay(
          new Intl.NumberFormat('pt-BR', {
            minimumFractionDigits: 2,
            maximumFractionDigits: 2,
          }).format(editingTransaction.amount)
        );
      } else {
        setAmountDisplay('');
      }
      setVencimento(editingTransaction.vencimento);
      setPagamento(editingTransaction.pagamento);
      setType(editingTransaction.type);
      setScope(editingTransaction.scope);
      setCategory(editingTransaction.category);
      setParcela(editingTransaction.parcela);
      setTotalParcelas(editingTransaction.totalParcelas);
      setNature(editingTransaction.nature);
      setPeriodicity(editingTransaction.periodicity || PeriodicityType.NONE);
    } else {
      setType(initialType);
    }
  }, [editingTransaction, initialType]);

  const handleAmountChange = (e: React.ChangeEvent<HTMLInputElement>) => {
    let value = e.target.value.replace(/\D/g, '');
    if (value === '') {
      setAmount(0);
      setAmountDisplay('');
      return;
    }
    const numericValue = parseInt(value, 10) / 100;
    setAmount(numericValue);

    setAmountDisplay(
      new Intl.NumberFormat('pt-BR', {
        minimumFractionDigits: 2,
        maximumFractionDigits: 2,
      }).format(numericValue)
    );
  };

  const handleSubmit = (e: React.FormEvent) => {
    e.preventDefault();

    const isCartao = category === ExpenseCategory.CARTAO;
    const isAmountValid = isCartao ? true : amount > 0;

    if (!description || !isAmountValid || !vencimento || !category) {
      alert("Por favor, preencha todos os campos obrigatórios (Categoria, Descrição, Valor e Vencimento).");
      return;
    }

    onSave({
      id: editingTransaction?.id,
      description,
      amount,
      vencimento,
      pagamento,
      category,
      parcela,
      totalParcelas,
      nature,
      periodicity: nature === ExpenseNature.ROUTINE ? periodicity : PeriodicityType.NONE,
      type,
      scope,
      multiplicar: !editingTransaction && multiplicar
    });
    onClose();
  };

  const showMultiplier = !editingTransaction && 
    totalParcelas && 
    parcela && 
    parseInt(totalParcelas) > parseInt(parcela);

  return (
    <div className="fixed inset-0 bg-black/50 backdrop-blur-sm flex items-center justify-center p-4 z-50">
      <div className="bg-white rounded-2xl w-full max-w-md p-6 shadow-2xl overflow-y-auto max-h-[90vh]">
        <div className="flex items-center justify-between mb-6">
          <h2 className="text-2xl font-bold text-slate-800">
            {editingTransaction ? 'Editar' : 'Novo'} {type}
          </h2>
          <span className="text-[10px] font-black uppercase tracking-widest px-3 py-1 rounded-full bg-slate-100 text-slate-500">
            {scope}
          </span>
        </div>

        <form onSubmit={handleSubmit} className="space-y-4">

          {/* Categoria is now first */}
          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Categoria</label>
            <select
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
              value={category}
              onChange={(e) => setCategory(e.target.value)}
              required
            >
              <option value="" disabled>Selecione uma categoria</option>
              {type === TransactionType.EXPENSE ? (
                Object.values(ExpenseCategory).map(g => (
                  <option key={g} value={g}>{g.toUpperCase()}</option>
                ))
              ) : type === TransactionType.INCOME ? (
                Object.values(IncomeCategory).map(i => (
                  <option key={i} value={i}>{i.toUpperCase()}</option>
                ))
              ) : (
                <option value="Investimento">INVESTIMENTO</option>
              )}
            </select>
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Descrição</label>
            <input
              type="text"
              required
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none transition-all"
              placeholder="Ex: Aluguel, Salário, CDB..."
              value={description}
              onChange={(e) => setDescription(e.target.value)}
            />
          </div>

          <div className="grid grid-cols-1 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Natureza</label>
              <select
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                value={nature}
                onChange={(e) => setNature(e.target.value as ExpenseNature)}
              >
                <option value={ExpenseNature.EVENTUAL}>Eventual</option>
                <option value={ExpenseNature.ROUTINE}>Rotineiro</option>
              </select>
            </div>

            {nature === ExpenseNature.ROUTINE && (
              <div className="animate-in fade-in slide-in-from-top-2 duration-300">
                <label className="block text-sm font-medium text-slate-600 mb-1">Frequência da Rotina</label>
                <select
                  className="w-full px-4 py-2 rounded-lg border border-blue-200 bg-blue-50/30 focus:ring-2 focus:ring-blue-500 outline-none"
                  value={periodicity}
                  onChange={(e) => setPeriodicity(e.target.value as PeriodicityType)}
                  required
                >
                  <option value="" disabled>Escolha a periodicidade</option>
                  <option value={PeriodicityType.WEEKLY}>Semanal</option>
                  <option value={PeriodicityType.MONTHLY}>Mensal</option>
                  <option value={PeriodicityType.SEMIANNUAL}>Semestral</option>
                  <option value={PeriodicityType.ANNUAL}>Anual</option>
                </select>
              </div>
            )}
          </div>

          <div>
            <label className="block text-sm font-medium text-slate-600 mb-1">Valor (R$) {category === ExpenseCategory.CARTAO && <span className="text-[10px] text-blue-400 font-normal italic">(Opcional para Cartão)</span>}</label>
            <input
              type="text"
              className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
              placeholder="0,00"
              value={amountDisplay}
              onChange={handleAmountChange}
            />
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Vencimento</label>
              <input
                type="date"
                required
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                value={vencimento}
                onChange={(e) => setVencimento(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1 text-[11px] leading-tight">Pagamento/Agendamento</label>
              <input
                type="date"
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                value={pagamento}
                onChange={(e) => setPagamento(e.target.value)}
              />
            </div>
          </div>

          <div className="grid grid-cols-2 gap-4">
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Parcela</label>
              <input
                type="text"
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Ex: 1"
                value={parcela}
                onChange={(e) => setParcela(e.target.value)}
              />
            </div>
            <div>
              <label className="block text-sm font-medium text-slate-600 mb-1">Total Parcelas</label>
              <input
                type="text"
                className="w-full px-4 py-2 rounded-lg border border-slate-200 focus:ring-2 focus:ring-blue-500 outline-none"
                placeholder="Ex: 1"
                value={totalParcelas}
                onChange={(e) => setTotalParcelas(e.target.value)}
              />
            </div>
          </div>

          {showMultiplier && (
            <div className="p-3 bg-blue-50 rounded-xl border border-blue-100 animate-in zoom-in-95 duration-200">
              <label className="block text-xs font-bold text-blue-700 uppercase mb-2">Multiplicar lançamentos?</label>
              <div className="flex gap-2">
                <button
                  type="button"
                  onClick={() => setMultiplicar(true)}
                  className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${multiplicar ? 'bg-blue-600 text-white shadow-md' : 'bg-white text-blue-600 border border-blue-200'}`}
                >
                  Sim
                </button>
                <button
                  type="button"
                  onClick={() => setMultiplicar(false)}
                  className={`flex-1 py-2 text-sm font-bold rounded-lg transition-all ${!multiplicar ? 'bg-slate-600 text-white shadow-md' : 'bg-white text-slate-400 border border-slate-200'}`}
                >
                  Não
                </button>
              </div>
            </div>
          )}

          <div className="flex gap-3 pt-4">
            <button
              type="button"
              onClick={onClose}
              className="flex-1 px-4 py-2 rounded-lg bg-slate-100 text-slate-600 font-medium hover:bg-slate-200 transition-colors"
            >
              Cancelar
            </button>
            <button
              type="submit"
              className="flex-1 px-4 py-2 rounded-lg bg-blue-600 text-white font-medium hover:bg-blue-700 transition-colors shadow-lg shadow-blue-200"
            >
              {editingTransaction ? 'Atualizar' : 'Salvar'}
            </button>
          </div>
        </form>
      </div>
    </div>
  );
};

